create or replace function LeadUtmBinding (&&Source&& varchar(2000), &&Medium&& varchar(2000), &&Campaign&& varchar(2000)) returns void
as $$
begin update &&Lead&& set &&MarketingGroup&& = (select mg.&&Id&& from &&MarketingGroup&& mg left join &&MarketingTag&& mt on mt.&&MarketingObject&& = mg.&&Id&& where mt.&&Name&& = &&Lead&&.&&UtmSource&& limit 1) where ($1 = '' or &&Lead&&.&&UtmSource&& = $1) and ($2 = '' or &&Lead&&.&&UtmMedium&& = $2) and ($3 = '' or &&Lead&&.&&UtmCampaign&& = $3);
update &&Lead&& set &&MarketingActivity&& = (select ma.&&Id&& from &&MarketingActivity&& ma left join &&MarketingTag&& mt on mt.&&MarketingObject&& = ma.&&Id&& where mt.&&Name&& = &&Lead&&.&&UtmMedium&& and ma.&&MarketingGroup&& = &&Lead&&.&&MarketingGroup&& limit 1) where ($1 = '' or &&Lead&&.&&UtmSource&& = $1) and ($2 = '' or &&Lead&&.&&UtmMedium&& = $2) and ($3 = '' or &&Lead&&.&&UtmCampaign&& = $3);
update &&Lead&& set &&MarketingEffect&& = (select me.&&Id&& from &&MarketingEffect&& me left join &&MarketingTag&& mt on mt.&&MarketingObject&& = me.&&Id&& where mt.&&Name&& = &&Lead&&.&&UtmCampaign&& and me.&&MarketingActivity&& = &&Lead&&.&&MarketingActivity&& limit 1) where ($1 = '' or &&Lead&&.&&UtmSource&& = $1) and ($2 = '' or &&Lead&&.&&UtmMedium&& = $2) and ($3 = '' or &&Lead&&.&&UtmCampaign&& = $3); end
$$ language plpgsql;

create or replace function MarketingGroupRecalc (p_Group bigint) returns void
as $$
begin
update &&MarketingBase&& mb set &&DirtyLeadCount&& = (select count(&&Id&&) from &&Lead&& where &&MarketingEffect&& = mb.&&Id&&), &&CleanLeadCount&& = (select count(&&Id&&) from &&Lead&& where &&MarketingEffect&& = mb.&&Id&& and &&IsDeleted&& <> 1 and &&Status&& <> 4), &&AcceptedLeadCount&& = (select count(&&Id&&) from &&Lead&& where &&MarketingEffect&& = mb.&&Id&& and &&IsDeleted&& <> 1 and &&Status&& in (1,2,3)), &&QualifiedLeadCount&& = (select count(&&Id&&) from &&Lead&& where &&MarketingEffect&& = mb.&&Id&& and &&IsDeleted&& <> 1 and &&Status&& in (2)) where mb.&&TypeUid&& = 'AFA958013CD15B42BB09408C03AAEAB9' and (select ma.&&MarketingGroup&& from &&MarketingEffect&& me left join &&MarketingActivity&& ma on ma.&&Id&& = me.&&MarketingActivity&& where me.&&Id&& = mb.&&Id&&) = $1;
update &&MarketingBase&& mb set &&DirtyLeadCount&& = (select count(&&Id&&) from &&Lead&& where &&MarketingActivity&& = mb.&&Id&&), &&CleanLeadCount&& = (select count(&&Id&&) from &&Lead&& where &&MarketingActivity&& = mb.&&Id&& and &&IsDeleted&& <> 1 and &&Status&& <> 4), &&AcceptedLeadCount&& = (select count(&&Id&&) from &&Lead&& where &&MarketingActivity&& = mb.&&Id&& and &&IsDeleted&& <> 1 and &&Status&& in (1,2,3)), &&QualifiedLeadCount&& = (select count(&&Id&&) from &&Lead&& where &&MarketingActivity&& = mb.&&Id&& and &&IsDeleted&& <> 1 and &&Status&& in (2)) where mb.TypeUid = 'D44A3B973248D14BAC2622B1B8461DD0' and (select MarketingGroup from MarketingActivity ma where ma.&&Id&& = mb.&&Id&&) = $1;
update &&MarketingBase&& mb set &&DirtyLeadCount&& = (select count(&&Id&&) from &&Lead&& where MarketingGroup = mb.&&Id&&), &&CleanLeadCount&& = (select count(&&Id&&) from &&Lead&& where MarketingGroup = mb.&&Id&& and &&IsDeleted&& <> 1 and &&Status&& <> 4), &&AcceptedLeadCount&& = (select count(&&Id&&) from &&Lead&& where MarketingGroup = mb.&&Id&& and &&IsDeleted&& <> 1 and &&Status&& in (1,2,3)), &&QualifiedLeadCount&& = (select count(&&Id&&) from &&Lead&& where MarketingGroup = mb.&&Id&& and &&IsDeleted&& <> 1 and &&Status&& in (2)) where mb.&&Id&& = $1;
end
$$ language plpgsql;

create or replace function MarketingActivityRecalc (activity bigint) returns void
as $$
begin update &&MarketingBase&& mb set &&DirtyLeadCount&& = (select count(&&Id&&) from &&Lead&& where &&MarketingActivity&& = mb.&&Id&&), &&CleanLeadCount&& = (select count(&&Id&&) from &&Lead&& where &&MarketingActivity&& = mb.&&Id&& and &&IsDeleted&& <> 1 and &&Status&& <> 4), &&AcceptedLeadCount&& = (select count(&&Id&&) from &&Lead&& where &&MarketingActivity&& = mb.&&Id&& and &&IsDeleted&& <> 1 and &&Status&& in (1,2,3)), &&QualifiedLeadCount&& = (select count(&&Id&&) from &&Lead&& where &&MarketingActivity&& = mb.&&Id&& and &&IsDeleted&& <> 1 and &&Status&& in (2)) where mb.&&TypeUid&& = 'AFA958013CD15B42BB09408C03AAEAB9' and (select &&MarketingActivity&& from &&MarketingEffect&& me where me.&&Id&& = mb.&&Id&&) = $1;
update &&MarketingBase&& mb set &&DirtyLeadCount&& = (select count(&&Id&&) from &&Lead&& where &&MarketingGroup&& = mb.&&Id&&), &&CleanLeadCount&& = (select count(&&Id&&) from &&Lead&& where &&MarketingGroup&& = mb.&&Id&& and &&IsDeleted&& <> 1 and &&Status&& <> 4), &&AcceptedLeadCount&& = (select count(&&Id&&) from &&Lead&& where &&MarketingGroup&& = mb.&&Id&& and &&IsDeleted&& <> 1 and &&Status&& in (1,2,3)), &&QualifiedLeadCount&& = (select count(&&Id&&) from &&Lead&& where &&MarketingGroup&& = mb.&&Id&& and &&IsDeleted&& <> 1 and &&Status&& in (2)) where mb.&&Id&& = $1; end
$$ language plpgsql;


create or replace function AddUpdateContractorPermissions(&&Uid&& uuid)
returns void

as
$$

declare 

v_PermissionId uuid;
v_User bigint;
v_Group bigint;
v_countCrm bigint;
v_OrganizationItemPosition bigint;
v_UserSecuritySetCacheId bigint;
v_PermissionRole  uuid;
v_OrganizationItemEmployee bigint;
v_Contractor bigint;

v_PermissionContactId uuid;
v_PermissionSaleId uuid;
v_PermissionRelationshipId uuid;
v_PermissionRoleUser uuid;

v_CRMContractorCreateElementPermissionId uuid;
v_CRMContractorIssuancePermissionId uuid;
v_ViewContractorPermissionId uuid;
v_EditContractorPermissionId uuid;
v_FullContractorPermissionId uuid;

v_CRMSaleIssuancePermissionId uuid;
v_ViewSalePermissionId uuid;
v_EditSalePermissionId uuid;
v_CRMSaleCreateElementPermissionId uuid ;
v_FullSalePermissionId uuid;

v_CRMContactCreateElementPermissionId uuid;
v_CRMContactIssuancePermissionId uuid;
v_ViewContactPermissionId uuid;
v_EditContactPermissionId uuid;
v_CRMContactFullAccessPermissionId uuid;

v_CRMInpaymentCreateElementPermissionId uuid;
v_ViewInpaymentPermissionId uuid;
v_EditInpaymentPermissionId uuid;
v_CRMInpaymentIssuanceElementPermissionId uuid;
v_CRMInpaymentFullAccessPermissionId uuid;

v_CRMRelationshipCreateElementPermissionId uuid;
v_ViewRelationshipPermissionId uuid;
v_EditRelationshipPermissionId uuid;
v_CRMRelationshipIssuanceElementPermissionId uuid;
v_CRMRelationshipFullAccessPermissionId uuid;

v_PermissionRoleTypeUser uuid;
v_PermissionRoleTypeInforms uuid;
v_PermissionRoleTypeParticipantWork uuid;
v_PermissionRoleTypeResponsible uuid;

v_AdminUser bigint;
v_AdminUid  uuid;
v_UserMask bigint;
v_PermissionRoleAuthor uuid;
v_NullUid uuid;
begin
      truncate table  &&RelationshipPersonPermUpd&&;      
      truncate table &&ContactPersonPermissionDel&&;
      truncate table &&SalePersonPermissionDel&&;

	select cp.&&PermissionId&&, cp.&&User&&,cp.&&Group&&,cp.&&OrganizationItemPosition&&,cp.&&UserSecuritySetCacheId&&,cp.&&PermissionRole&&,cp.&&OrganizationItemEmployee&&,cp.&&Contractor&&
        from &&ContractorPersonPermission&& cp
        where cp.&&Uid&& = $1
        into v_PermissionId, v_User, v_Group, v_OrganizationItemPosition, v_UserSecuritySetCacheId, v_PermissionRole, v_OrganizationItemEmployee, v_Contractor;

           /*Если нет подчиненных элементов то и считать нечего*/
        select sum(a)  from (
            select count(1) as a from &&Relationship&& c where c.&&Contractor&& = v_Contractor
              union all
            select count(1) from &&Sale&& c where c.&&Contractor&& =v_Contractor 
              union all
            select count(1) from &&Relationship&& c left join &&Contact&& con on  c.&&Contact&&=con.&&Id&& where con.&&Contractor&&=v_Contractor
              union all
            select count(1) from &&Relationship&& c left join &&Sale&& con on  c.&&Sale&&=con.&&Id&& where con.&&Contractor&&=v_Contractor
              union all
            select count(1) from &&Contact&& c where c.&&Contractor&&=v_Contractor
        ) a
        into v_countCrm ;

        IF (v_countCrm=0) then return; end if;

        v_PermissionRoleAuthor='B4565CC1-7CB3-4201-B7BD-15872D1E7F92';
        v_NullUid='00000000-0000-0000-0000-000000000000';
        v_AdminUid='f0e949bf-4da4-4c02-b04c-ca61964b4fe8';
        v_UserMask = 72057594037927936; -- побитовый сдвиг влево 1 на 56 разрядов (2 ^ 56) 1055 
        v_CRMContractorCreateElementPermissionId = '44ED88D4-A466-4fed-B194-B8288560CB48';
        v_CRMContractorIssuancePermissionId = '1CD25727-7CE6-443c-84BD-7975822C79E6';
        v_ViewContractorPermissionId = '9219C9AB-7E68-47B1-8939-FF6FC4439DA0';
        v_EditContractorPermissionId = '8C932B94-2F9C-488E-A36F-949A11C9741E';
        v_FullContractorPermissionId = 'E612615C-D5E2-4c4b-9DF0-B4D9EEB983A5';

        v_CRMSaleIssuancePermissionId = 'F2141650-BB6D-4e3a-BB62-C0F071CF8EEA';
        v_ViewSalePermissionId = 'AAE16346-B0E6-4949-ACAB-0914C573DE55';
        v_EditSalePermissionId = 'AF2CEF4B-F639-49B4-BD88-363F20BD5A74';
        v_CRMSaleCreateElementPermissionId = '7DB77821-D6D3-4dd2-AD1B-798330506ADC';
        v_FullSalePermissionId = 'DB60BB49-0DE1-46ee-8CE8-DCD59DB93351';

        v_CRMContactCreateElementPermissionId = 'BCE45C2C-CAE1-41df-8A0A-C54E0409E8B5';
        v_CRMContactIssuancePermissionId = '05D9000F-0600-49a6-8AE8-DA1DA72BFCF1';
        v_ViewContactPermissionId = '3626682F-B657-419E-9A8E-392C14ABE455';
        v_EditContactPermissionId = 'ABC752AD-3623-4F14-A47F-121999890D2C';
        v_CRMContactFullAccessPermissionId = '76B481D5-2E07-4417-9098-A57DE879FA56';

        v_CRMInpaymentCreateElementPermissionId = 'D130BB5F-6A26-4e37-B62C-F3B443E3BF53';
        v_ViewInpaymentPermissionId  = '837FF0F3-03A7-4A17-86EA-A72B3AB4886B';
        v_EditInpaymentPermissionId  = 'E23802D7-F3B5-431E-A72E-7133C3C9343F';
        v_CRMInpaymentIssuanceElementPermissionId  = 'ACF5606C-B566-426b-BAEC-E74061095BEB';
        v_CRMInpaymentFullAccessPermissionId  = 'A27A46F9-BCD8-4e82-AE49-E58675DE52D7';

        v_CRMRelationshipCreateElementPermissionId = 'BA5E9414-B347-4eaa-A019-14D4FA02F5E2';
        v_ViewRelationshipPermissionId = '186D4CC4-6924-4848-93AC-6D8DE389CB08';
        v_EditRelationshipPermissionId  = '0B980531-D097-4EC1-8616-56E6AB15770E';
        v_CRMRelationshipIssuanceElementPermissionId  = '679876A7-8882-43d4-8FC2-3E7C9DB58ADB';
        v_CRMRelationshipFullAccessPermissionId = '38A0AC5D-8D9C-4BB5-BDBA-A0E6CFD43C30';


        v_PermissionRoleTypeUser  =  'ED43E50F-6085-47BD-9A28-E43246E476A8';
        v_PermissionRoleTypeInforms  = '21888C0C-8BCA-4B26-AF13-4C497EECCED6';
        v_PermissionRoleTypeParticipantWork  = '9A945D2E-BCFA-4AF4-8653-9A67A5ED6386';
        v_PermissionRoleTypeResponsible  = 'CE4D6154-E36E-406b-8BE9-25266C5BDD15';

 select u.&&Id&& from &&User&& u where u.&&Uid&& = v_AdminUid    
        into v_AdminUser;

    v_PermissionRoleUser=
        case
          when v_PermissionRole = v_PermissionRoleTypeInforms then v_PermissionRoleTypeUser
          when v_PermissionRole= v_PermissionRoleTypeParticipantWork then v_PermissionRoleTypeUser
          when v_PermissionRole= v_PermissionRoleTypeResponsible then v_PermissionRoleTypeUser
          else v_PermissionRole
        end ;

    v_PermissionContactId=
    case
      when v_PermissionId= v_CRMContractorCreateElementPermissionId then v_CRMContactCreateElementPermissionId
      when v_PermissionId= v_CRMContractorIssuancePermissionId then v_CRMContactIssuancePermissionId
      when v_PermissionId= v_ViewContractorPermissionId then v_ViewContactPermissionId
      when v_PermissionId= v_EditContractorPermissionId then v_EditContactPermissionId
      when v_PermissionId= v_FullContractorPermissionId then v_CRMContactFullAccessPermissionId
      else v_PermissionId
   end;

   v_PermissionSaleId=
   case
      when v_PermissionId= v_CRMContractorCreateElementPermissionId then v_CRMSaleCreateElementPermissionId
      when v_PermissionId= v_CRMContractorIssuancePermissionId then v_CRMSaleIssuancePermissionId
      when v_PermissionId= v_ViewContractorPermissionId then v_ViewSalePermissionId
      when v_PermissionId= v_EditContractorPermissionId then v_EditSalePermissionId
      when v_PermissionId= v_FullContractorPermissionId then v_FullSalePermissionId
      else v_PermissionId
   end;

   v_PermissionRelationshipId=
   case
      when v_PermissionId= v_CRMContractorCreateElementPermissionId then v_CRMRelationshipCreateElementPermissionId
      when v_PermissionId= v_CRMContractorIssuancePermissionId then v_CRMRelationshipIssuanceElementPermissionId
      when v_PermissionId= v_ViewContractorPermissionId then v_ViewRelationshipPermissionId
      when v_PermissionId= v_EditContractorPermissionId then v_EditRelationshipPermissionId
      when v_PermissionId= v_FullContractorPermissionId then v_CRMRelationshipFullAccessPermissionId
      else v_PermissionId
   end;

        update &&ContactPersonPermission&& set &&InheritedFromNumber&&= 1 where &&Id&& in
            (select c.&&Id&&
            from &&ContactPersonPermission&& c
            left join &&Contact&& cp on cp.&&Id&&=c.&&Contact&& 
        where
            c.&&PermissionId&& = v_PermissionContactId and c.&&UserSecuritySetCacheId&& = v_UserSecuritySetCacheId and
            &&InheritedFromNumber&& > 0 and cp.&&Contractor&& = v_Contractor);

        insert into &&ContactPersonPermissionDel&& (&&PermissionId&&, &&User&&, &&Group&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Contact&&, &&UserSecuritySetCacheId&&, &&Uid&&, &&InheritedFromNumber&&, &&OrganizationItemPosition&&)
        select v_PermissionContactId as &&PermissionId&&, v_User &&User&&, v_Group &&Group&&, v_PermissionRole, v_OrganizationItemEmployee as &&OrganizationItemEmployee&&, c.&&Id&& as &&Contact&&, v_UserSecuritySetCacheId as &&UserSecuritySetCacheId&&, uuid_generate_v4() as &&Uid&&,count(1) as &&InheritedFromNumber&&  ,v_OrganizationItemPosition as &&OrganizationItemPosition&&
        from &&Contact&& c
            left join &&ContractorPersonPermission&& t on t.&&Contractor&&=c.&&Contractor&&
            left outer join &&ContactPersonPermission&& cp on 
                 cp.&&Contact&&=c.&&Id&& and 
                 cp.&&PermissionId&&=v_PermissionContactId and 
                 cp.&&UserSecuritySetCacheId&&=v_UserSecuritySetCacheId and 
                 cp.&&InheritedFromNumber&& > 0 and
                 cp.&&PermissionRole&&=v_permissionRole
        where  t.&&Contractor&& is not null 
            and cp.&&Contact&& is null 
            and t.&&PermissionId&& = v_PermissionId and t.&&UserSecuritySetCacheId&& = v_UserSecuritySetCacheId
            and c.&&InheritPermissions&& = 1
            and c.&&Contractor&& = v_Contractor
            and t.&&PermissionRole&&=v_permissionRole
        group by t.&&PermissionId&&, t.&&User&&, t.&&Group&&,t.&&PermissionRole&&,t.&&OrganizationItemEmployee&&,c.&&Id&&,t.&&UserSecuritySetCacheId&&,t.&&OrganizationItemPosition&&;

  /*Перезаписать реальных пользователей в ответственных */
      update &&ContactPersonPermissionDel&& 
      set 
          &&User&& = (select contr.&&Responsible&& from &&Contact&& con left join &&Contractor&& contr on contr.&&Id&&=con.&&Contractor&& where con.&&Id&&=&&Contact&&),
          &&UserSecuritySetCacheId&&= 
		  (select (contr.&&Responsible&&|v_usermask) from &&Contact&& con left join &&Contractor&& contr on contr.&&Id&&=con.&&Contractor&& where con.&&Id&&=&&Contact&&)
      where &&PermissionRole&&=v_PermissionRoleTypeResponsible;

	  /*Перезаписать реальных пользователей в ответственных */
      update &&ContactPersonPermissionDel&&
      set 
          &&User&&= (select &&CreationAuthor&& from &&Contact&& con where con.&&Id&&=&&Contact&&),
          &&UserSecuritySetCacheId&&= (select (&&CreationAuthor&&|v_usermask) from &&Contact&& con where con.&&Id&&=&&Contact&&)
      where &&PermissionRole&&=v_PermissionRoleAuthor;

        insert into &&ContactPersonPermission&& (&&Id&&,&&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Contact&&,&&UserSecuritySetCacheId&&,&&Uid&&,&&InheritedFromNumber&&,&&OrganizationItemPosition&&)
        select nextval('G_CONTACTPERSONPERMISSION') &&Id&&,&&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Contact&&,&&UserSecuritySetCacheId&&,uuid_generate_v4(),&&InheritedFromNumber&&,v_OrganizationItemPosition from &&ContactPersonPermissionDel&&;


  update &&SalePersonPermission&& set &&InheritedFromNumber&&=1
    where &&Id&& in
    (select c.&&Id&&
        from &&SalePersonPermission&& c
          left join &&Sale&& s on s.&&Id&&=c.&&Sale&& 
        where s.&&Contractor&&=v_Contractor and
        &&PermissionId&&=v_PermissionSaleId and
        &&UserSecuritySetCacheId&& =case c.&&PermissionRole&& 
		         when v_PermissionRoleAuthor then  ((select &&Author&& from &&Sale&& con where con.&&Id&&=c.&&Sale&&)|v_UserMask)
		         when v_PermissionRoleTypeResponsible then  (select (&&Responsible&&|v_UserMask) from &&Sale&& con where con.&&Id&&=&&Sale&&)
	           ELSE &&UserSecuritySetCacheId&&
	      end
        and &&PermissionRole&&=v_PermissionRole
        and &&InheritedFromNumber&& > 0);



insert into &&SalePersonPermissionDel&& (&&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Sale&&,&&UserSecuritySetCacheId&&,&&Uid&&,&&InheritedFromNumber&&,&&OrganizationItemPosition&&)
select v_PermissionSaleId as &&PermissionId&&, v_User &&User&&, v_Group as &&Group&&,v_PermissionRole, v_OrganizationItemEmployee as &&OrganizationItemEmployee&&,c.&&Id&& as &&Sale&&,v_UserSecuritySetCacheId as &&UserSecuritySetCacheId&&,
uuid_generate_v4() as &&Uid&&,1 as &&InheritedFromNumber&& ,v_OrganizationItemPosition as &&OrganizationItemPosition&&
from &&Sale&& c
 left join &&ContractorPersonPermission&& t on t.&&Contractor&&=c.&&Contractor&& 
 left outer join &&SalePersonPermission&& cp on 
     cp.&&Sale&&=c.&&Id&& and 
     cp.&&PermissionId&&=v_PermissionSaleId and 
     cp.&&UserSecuritySetCacheId&&=v_UserSecuritySetCacheId and 
     cp.&&InheritedFromNumber&& > 0 and  
     cp.&&PermissionRole&&=v_permissionRole
where  t.&&Contractor&& is not null 
and cp.&&Sale&& is null 
 and t.&&PermissionId&&=v_PermissionId and t.&&UserSecuritySetCacheId&&=v_UserSecuritySetCacheId
  and c.&&InheritPermissions&&=1
    and t.&&PermissionRole&&=v_permissionRole
    and c.&&Contractor&&=v_contractor
  group by t.&&PermissionId&& ,t.&&User&&,t.&&Group&&,t.&&PermissionRole&&,t.&&OrganizationItemEmployee&&,c.&&Id&&,t.&&UserSecuritySetCacheId&& ,t.&&OrganizationItemPosition&&;

/*Перезаписать реальных пользователей в ответственных */
      update &&SalePersonPermissionDel&& 
      set 
          &&User&& = (select &&Responsible&& from &&Sale&& con  where con.&&Id&&=&&Sale&&),
          &&UserSecuritySetCacheId&&= (select (&&Responsible&&|v_UserMask) from &&Sale&& con  where con.&&Id&&=&&Sale&&)
      where &&PermissionRole&&=v_PermissionRoleTypeResponsible;

	  /*Перезаписать реальных пользователей в ответственных */
      update &&SalePersonPermissionDel&&
      set 
          &&User&&= (select &&Author&& from &&Sale&& con where con.&&Id&&=&&Sale&&),
          &&UserSecuritySetCacheId&&= (select (&&Author&&|v_usermask) from &&Sale&& con where con.&&Id&&=&&Sale&&)
      where &&PermissionRole&&=v_PermissionRoleAuthor;

  insert into &&SalePersonPermission&& (&&Id&&,&&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Sale&&,&&UserSecuritySetCacheId&&,&&Uid&&,&&InheritedFromNumber&&,&&OrganizationItemPosition&&)
  select nextval('G_SALEPERSONPERMISSION') &&Id&&,&&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Sale&&,&&UserSecuritySetCacheId&&,uuid_generate_v4(),&&InheritedFromNumber&&,v_OrganizationItemPosition from &&SalePersonPermissionDel&&;



delete from &&RelationshipPersonPermission&& where &&Id&& in (select c.&&Id&& from &&RelationshipPersonPermission&& c
left join &&Relationship&& r on r.&&Contractor&&=v_Contractor and c.&&Relationship&&=r.&&Id&&
where 
 &&PermissionId&&=v_PermissionRelationshipId 
 and &&UserSecuritySetCacheId&&
 =case c.&&PermissionRole&& 
		when v_PermissionRoleAuthor then  ((select &&CreationAuthor&& from &&Relationship&& con where con.&&Id&&=c.&&Relationship&&)|v_usermask)
		when v_PermissionRoleTypeResponsible then  (select (&&Relationship&&|v_usermask) from &&Relationship&& con where con.&&Id&&=&&Relationship&&)
	 ELSE v_UserSecuritySetCacheId
	 end
 and r.&&Contractor&&=v_Contractor
 and r.&&InheritPermissions&&=1
 and c.&&InheritedFromNumber&& > 0
   and (
        ((c.&&PermissionRole&& =v_permissionRoleTypeParticipantWork and c.&&User&&=v_adminUser and c.&&User&&=v_user ) or (c.&&PermissionRole&& !=v_permissionRoleTypeParticipantWork and c.&&PermissionRole&& !=v_permissionRoleTypeInforms ))/*В случае с участниками берем только если пришел системный пользователь*/
        and ((c.&&PermissionRole&& =v_PermissionRoleTypeInforms and c.&&User&&=v_adminUser and c.&&User&&=v_user ) or (c.&&PermissionRole&& !=v_permissionRoleTypeInforms and c.&&PermissionRole&& !=v_permissionRoleTypeParticipantWork))
	     )
 );

/*добавить недостающие   из контрагентов*/

  insert into &&RelationshipPersonPermUpd&& (&&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Relationship&&,&&UserSecuritySetCacheId&&,&&Uid&&,&&InheritedFromNumber&&,&&OrganizationItemPosition&&)
select v_PermissionRelationshipId as &&PermissionId&& ,v_User as &&User&&,v_Group as &&Group&&, v_PermissionRole as &&PermissionRole&&,v_OrganizationItemEmployee as &&OrganizationItemEmployee&&,c.&&Id&& as &&Relationship&&,v_UserSecuritySetCacheId as &&UserSecuritySetCacheId&&,uuid_generate_v4() as &&Uid&& ,count(1) as &&InheritedFromNumber&&,v_OrganizationItemPosition as &&OrganizationItemPosition&&
from &&Relationship&& c
 left join &&ContractorPersonPermission&& t on t.&&Contractor&&=c.&&Contractor&& 
 left outer join &&RelationshipPersonPermission&& cp on 
        cp.&&Relationship&&=c.&&Id&& and 
        cp.&&PermissionId&&=v_PermissionRelationshipId and 
        cp.&&UserSecuritySetCacheId&&=v_UserSecuritySetCacheId and 
        cp.&&InheritedFromNumber&& > 0 and
        cp.&&PermissionRole&&=t.&&PermissionRole&&
where
  t.&&Contractor&& is not null 
     and cp.&&Relationship&& is null 
     and t.&&PermissionId&&=v_PermissionId and
      t.&&UserSecuritySetCacheId&&=v_UserSecuritySetCacheId
      and c.&&InheritPermissions&&=1
      and c.&&Contractor&&=v_Contractor
       and t.&&PermissionRole&&=v_permissionRole
       and t.&&PermissionRole&&=
		case 
	 when t.&&PermissionRole&&=v_PermissionRoleTypeParticipantWork and t.&&User&&!=v_adminUser then  v_NullUid
	 when t.&&PermissionRole&&=v_PermissionRoleTypeInforms and t.&&User&&!=v_adminUser then  v_NullUid
	 else 
	 t.&&PermissionRole&&
	 end
  group by t.&&PermissionId&& ,t.&&User&&,t.&&Group&&,t.&&PermissionRole&&,t.&&OrganizationItemEmployee&&,c.&&Id&&,t.&&UserSecuritySetCacheId&& ,t.&&OrganizationItemPosition&& ;

  /*Добавить пермишены реальных пользователей для исполнителей*/
insert into &&RelationshipPersonPermUpd&& (&&PermissionId&&,&&User&&
      ,&&Group&&
      ,&&OrganizationItemPosition&&
      ,&&UserSecuritySetCacheId&&
      ,&&PermissionRole&&
      ,&&OrganizationItemEmployee&&
      ,&&Relationship&&
      ,&&InheritedFromNumber&&
      )
select &&PermissionId&&
      ,m.&&UserID&& 
      ,&&Group&&
      ,&&OrganizationItemPosition&&
      ,m.&&UserID&&|v_usermask as  UserSecuritySetCacheId
      ,c.&&PermissionRole&&
      ,&&OrganizationItemEmployee&&
      ,&&Relationship&&
      ,1
	   from &&RelationshipUser&& m
left join &&RelationshipPersonPermUpd&& c on m.&&RelationshipID&&=c.&&Relationship&&
where &&PermissionRole&& =v_PermissionRoleTypeParticipantWork and &&User&&=v_adminUser and m.&&Status&&=0 
group by c.&&PermissionId&& ,c.&&User&&,c.&&Group&&,c.&&PermissionRole&&,c.&&OrganizationItemEmployee&&,c.&&UserSecuritySetCacheId&& ,c.&&OrganizationItemPosition&&,m.&&UserID&&,&&Relationship&&;

/*Добавить пермишены реальных пользователей для исполнителей*/
insert into &&RelationshipPersonPermUpd&& (&&PermissionId&&,&&User&&
      ,&&Group&&
      ,&&OrganizationItemPosition&&
      ,&&UserSecuritySetCacheId&&
      ,&&PermissionRole&&
      ,&&OrganizationItemEmployee&&
      ,&&Relationship&&
      ,&&InheritedFromNumber&&
      )
select &&PermissionId&&
      ,m.&&UserID&&
      ,&&Group&&
      ,&&OrganizationItemPosition&&
      ,m.&&UserID&&|v_usermask as UserSecuritySetCacheId
      ,c.&&PermissionRole&&
      ,&&OrganizationItemEmployee&&
      ,&&Relationship&&
      ,1
	   from &&RelationshipUser&& m
left join &&RelationshipPersonPermUpd&& c on m.&&RelationshipID&&=c.&&Relationship&&
where &&PermissionRole&& =v_PermissionRoleTypeInforms and &&User&&=v_adminUser and m.&&Status&&=1 
group by c.&&PermissionId&&, c.&&User&&, c.&&Group&&, c.&&PermissionRole&&, c.&&OrganizationItemEmployee&&, c.&&UserSecuritySetCacheId&&, c.&&OrganizationItemPosition&&, m.&&UserID&&, &&Relationship&&;

      /*Перезаписать реальных пользователей в ответственных */
        update &&RelationshipPersonPermUpd&&
      set 
          &&User&&= (select &&CreationAuthor&& from &&Relationship&& con where con.&&Id&&=&&Relationship&&),
          &&UserSecuritySetCacheId&&= (select (&&CreationAuthor&&|v_usermask) from &&Relationship&& con where con.&&Id&&=&&Relationship&&)
      where &&PermissionRole&&=v_PermissionRoleAuthor;

insert into &&RelationshipPersonPermission&& (&&Id&&,&&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Relationship&&,&&UserSecuritySetCacheId&&,&&Uid&&,&&InheritedFromNumber&&,&&OrganizationItemPosition&&)
select  nextval('G_RelationshipPERSONPERMISSION')  &&Id&&,t.&&PermissionId&& ,t.&&User&&,t.&&Group&&,t.&&PermissionRole&&,t.&&OrganizationItemEmployee&&,&&Relationship&&,t.&&UserSecuritySetCacheId&&,uuid_generate_v4() ,1 ,t.&&OrganizationItemPosition&&
from  &&RelationshipPersonPermUpd&& t;
delete from  &&RelationshipPersonPermUpd&&;

 insert into &&RelationshipPersonPermission&& (&&Id&&,&&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Relationship&&,&&UserSecuritySetCacheId&&,&&Uid&&,&&InheritedFromNumber&&,&&OrganizationItemPosition&&)
select nextval('G_RelationshipPERSONPERMISSION') as &&Id&&,v_PermissionRelationshipId as &&PermissionId&& ,v_User as &&User&&,v_Group as &&Group&&, v_PermissionRole as &&PermissionRole&&,v_OrganizationItemEmployee as &&OrganizationItemEmployee&&,c.&&Id&& as &&Relationship&&,v_UserSecuritySetCacheId as &&UserSecuritySetCacheId&&,uuid_generate_v4() as &&Uid&& ,count(1) as &&InheritedFromNumber&&,v_OrganizationItemPosition as &&OrganizationItemPosition&&
from &&Relationship&& c
 left join &&ContactPersonPermission&& t on t.&&Contact&&=c.&&Contact&& 
 left outer join &&RelationshipPersonPermission&& cp on cp.&&Relationship&&=c.&&Id&& and cp.&&PermissionId&&=v_PermissionRelationshipId and cp.&&UserSecuritySetCacheId&&=v_UserSecuritySetCacheId 
 and cp.&&InheritedFromNumber&& > 0
 left join &&Contact&& con on con.&&Contractor&&=v_Contractor and c.&&Contact&&=con.&&Id&&
where
  t.&&Contact&& is not null 
     and cp.&&Relationship&& is null 
     and t.&&PermissionId&&=v_PermissionContactId
     and t.&&UserSecuritySetCacheId&&=v_UserSecuritySetCacheId
      and c.&&InheritPermissions&&=1
      and c.&&Contractor&& is null
  group by t.&&PermissionId&& ,t.&&User&&,t.&&Group&&,t.&&PermissionRole&&,t.&&OrganizationItemEmployee&&, c.&&Id&&,t.&&UserSecuritySetCacheId&& ,t.&&OrganizationItemPosition&& ;

end

$$
language plpgsql;


create or replace function DelUpdateContractorPermissions (
        &&permissionId&& uuid,
        &&userSecuritySetCacheId&& bigint,
        &&ContractorId&& bigint,
        &&permissionRole&& uuid
        )

returns void        

as
$$

declare
v_PermissionContactId uuid;
v_PermissionSaleId uuid;
v_PermissionInpaymentId uuid;
v_PermissionRelationshipId uuid;

v_CRMContractorCreateElementPermissionId uuid;
v_CRMContractorIssuancePermissionId uuid;
v_ViewContractorPermissionId uuid;
v_EditContractorPermissionId uuid;
v_FullContractorPermissionId uuid;

v_CRMSaleIssuancePermissionId uuid;
v_ViewSalePermissionId uuid;
v_EditSalePermissionId uuid;
v_CRMSaleCreateElementPermissionId uuid ;
v_FullSalePermissionId uuid;

v_CRMContactCreateElementPermissionId uuid;
v_CRMContactIssuancePermissionId uuid;
v_ViewContactPermissionId uuid;
v_EditContactPermissionId uuid;
v_CRMContactFullAccessPermissionId uuid;

v_CRMInpaymentCreateElementPermissionId uuid;
v_ViewInpaymentPermissionId uuid;
v_EditInpaymentPermissionId uuid;
v_CRMInpaymentIssuanceElementPermissionId uuid;
v_CRMInpaymentFullAccessPermissionId uuid;

v_CRMRelationshipCreateElementPermissionId uuid;
v_ViewRelationshipPermissionId uuid;
v_EditRelationshipPermissionId uuid;
v_CRMRelationshipIssuanceElementPermissionId uuid;
v_CRMRelationshipFullAccessPermissionId uuid;
v_PermissionRoleTypeInforms uuid;
v_PermissionRoleTypeParticipantWork uuid;
v_AdminUser bigint;
v_AdminUid  uuid;
v_PermissionRoleAuthor uuid;
v_PermissionRoleTypeResponsible uuid;
v_UserMask bigint;

begin

v_UserMask = 72057594037927936; -- побитовый сдвиг влево 1 на 56 разрядов (2 ^ 56) 1055
v_PermissionRoleAuthor = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92';
v_PermissionRoleTypeResponsible = 'CE4D6154-E36E-406b-8BE9-25266C5BDD15';

v_CRMContractorCreateElementPermissionId = '44ED88D4-A466-4fed-B194-B8288560CB48';
v_CRMContractorIssuancePermissionId = '1CD25727-7CE6-443c-84BD-7975822C79E6';
v_ViewContractorPermissionId = '9219C9AB-7E68-47B1-8939-FF6FC4439DA0';
v_EditContractorPermissionId = '8C932B94-2F9C-488E-A36F-949A11C9741E';
v_FullContractorPermissionId = 'E612615C-D5E2-4c4b-9DF0-B4D9EEB983A5';


v_CRMSaleIssuancePermissionId = 'F2141650-BB6D-4e3a-BB62-C0F071CF8EEA';
v_ViewSalePermissionId = 'AAE16346-B0E6-4949-ACAB-0914C573DE55';
v_EditSalePermissionId = 'AF2CEF4B-F639-49B4-BD88-363F20BD5A74';
v_CRMSaleCreateElementPermissionId = '7DB77821-D6D3-4dd2-AD1B-798330506ADC';
v_FullSalePermissionId = 'DB60BB49-0DE1-46ee-8CE8-DCD59DB93351';

v_CRMContactCreateElementPermissionId = 'BCE45C2C-CAE1-41df-8A0A-C54E0409E8B5';
v_CRMContactIssuancePermissionId = '05D9000F-0600-49a6-8AE8-DA1DA72BFCF1';
v_ViewContactPermissionId = '3626682F-B657-419E-9A8E-392C14ABE455';
v_EditContactPermissionId = 'ABC752AD-3623-4F14-A47F-121999890D2C';
v_CRMContactFullAccessPermissionId = '76B481D5-2E07-4417-9098-A57DE879FA56';

v_CRMInpaymentCreateElementPermissionId = 'D130BB5F-6A26-4e37-B62C-F3B443E3BF53';
v_ViewInpaymentPermissionId  = '837FF0F3-03A7-4A17-86EA-A72B3AB4886B';
v_EditInpaymentPermissionId  = 'E23802D7-F3B5-431E-A72E-7133C3C9343F';
v_CRMInpaymentIssuanceElementPermissionId  = 'ACF5606C-B566-426b-BAEC-E74061095BEB';
v_CRMInpaymentFullAccessPermissionId  = 'A27A46F9-BCD8-4e82-AE49-E58675DE52D7';

v_CRMRelationshipCreateElementPermissionId = 'BA5E9414-B347-4eaa-A019-14D4FA02F5E2';
v_ViewRelationshipPermissionId = '186D4CC4-6924-4848-93AC-6D8DE389CB08';
v_EditRelationshipPermissionId  = '0B980531-D097-4EC1-8616-56E6AB15770E';
v_CRMRelationshipIssuanceElementPermissionId  = '679876A7-8882-43d4-8FC2-3E7C9DB58ADB';
v_CRMRelationshipFullAccessPermissionId = '38A0AC5D-8D9C-4BB5-BDBA-A0E6CFD43C30';

v_PermissionRoleTypeInforms  = '21888C0C-8BCA-4B26-AF13-4C497EECCED6';
v_PermissionRoleTypeParticipantWork  = '9A945D2E-BCFA-4AF4-8653-9A67A5ED6386';
v_AdminUid='f0e949bf-4da4-4c02-b04c-ca61964b4fe8';

 select u.&&Id&& from &&User&& u where u.&&Uid&& = v_AdminUid  into v_AdminUser;

v_PermissionContactId =
case
        when $1= v_CRMContractorCreateElementPermissionId then v_CRMContactCreateElementPermissionId
        when $1= v_CRMContractorIssuancePermissionId then v_CRMContactIssuancePermissionId
        when $1= v_ViewContractorPermissionId then v_ViewContactPermissionId
        when $1= v_EditContractorPermissionId then v_EditContactPermissionId
        when $1= v_FullContractorPermissionId then v_CRMContactFullAccessPermissionId
        else $1
end;
v_PermissionSaleId=
case
        when $1= v_CRMContractorCreateElementPermissionId then v_CRMSaleCreateElementPermissionId
        when $1= v_CRMContractorIssuancePermissionId then v_CRMSaleIssuancePermissionId
        when $1= v_ViewContractorPermissionId then v_ViewSalePermissionId
        when $1= v_EditContractorPermissionId then v_EditSalePermissionId
        when $1= v_FullContractorPermissionId then v_FullSalePermissionId
        else $1
end;

v_PermissionInpaymentId=
case
        when $1= v_CRMSaleCreateElementPermissionId then v_CRMInpaymentCreateElementPermissionId
        when $1= v_CRMSaleIssuancePermissionId then v_CRMInpaymentIssuanceElementPermissionId
        when $1= v_ViewSalePermissionId then v_ViewInpaymentPermissionId
        when $1= v_EditSalePermissionId then v_EditInpaymentPermissionId
        when $1= v_FullSalePermissionId then v_CRMInpaymentFullAccessPermissionId
        else $1
end ;
v_PermissionRelationshipId=
case
        when $1= v_CRMContractorCreateElementPermissionId then v_CRMRelationshipCreateElementPermissionId
        when $1= v_CRMContractorIssuancePermissionId then v_CRMRelationshipIssuanceElementPermissionId
        when $1= v_ViewContractorPermissionId then v_ViewRelationshipPermissionId
        when $1= v_EditContractorPermissionId then v_EditRelationshipPermissionId
        when $1= v_FullContractorPermissionId then v_CRMRelationshipFullAccessPermissionId
        else $1
end;

insert into &&ContactPersonPermissionDel&& (&&ContactId&&,&&PermissionId&&,&&UserSecuritySetCacheId&&,&&Contact&&)
select c.&&Id&& as &&ContactId&&,c.&&PermissionId&&,c.&&UserSecuritySetCacheId&&,&&Contact&&
from &&ContactPersonPermission&& c
inner join &&Contact&& con on con.&&Id&&=c.&&Contact&&
where  c.&&InheritedFromNumber&& > 0 and 
c.&&PermissionId&&=v_PermissionContactId and c.&&UserSecuritySetCacheId&&=
          case c.&&PermissionRole&& 
        		when v_PermissionRoleAuthor then  ((select &&CreationAuthor&& from &&Contact&& con where con.&&Id&&=c.&&Contact&&)|v_usermask)
		        when v_PermissionRoleTypeResponsible then  
		              (select (contr.&&Responsible&&|v_usermask) from &&Contact&& con left join &&Contractor&& contr on contr.&&Id&&=con.&&Contractor&& where con.&&Id&&=&&Contact&&)
	          ELSE $2
	        end
    and c.&&PermissionRole&&=$4
    and con.&&Contractor&&=$3;

update &&ContactPersonPermission&& set &&InheritedFromNumber&&=&&InheritedFromNumber&&-1 where &&Id&& in
    (select c.&&Id&&
    from &&ContactPersonPermission&& c
    join &&ContactPersonPermissionDel&& ct on ct.&&ContactId&&=c.&&Id&&
    where ct.&&ContactId&&=c.&&Id&&);

delete from &&ContactPersonPermission&& where &&InheritedFromNumber&& <= 0;

insert into &&SalePersonPermissionDel&& (&&SaleId&&,&&PermissionId&&,&&Sale&&,&&UserSecuritySetCacheId&&)
select c.&&Id&&,c.&&PermissionId&&,c.&&Sale&&,c.&&UserSecuritySetCacheId&&
from &&SalePersonPermission&& c
inner join &&Sale&& con on con.&&Id&&=c.&&Sale&&
where  c.&&InheritedFromNumber&& > 0
        and con.&&Contractor&&=$3 and
        c.&&PermissionId&&=v_PermissionSaleId and c.&&UserSecuritySetCacheId&&=
        case c.&&PermissionRole&& 
	     when v_PermissionRoleAuthor then  ((select &&Author&& from &&Sale&& con where con.&&Id&&=c.&&Sale&&)|v_usermask)
				when v_PermissionRoleTypeResponsible then  ((select &&Responsible&& from &&Sale&& con where con.&&Id&&=c.&&Sale&&)|v_usermask)
			 ELSE $2
			 end
			 and c.&&PermissionRole&&=$4;

update &&SalePersonPermission&& set &&InheritedFromNumber&& = &&InheritedFromNumber&& - 1  where &&Id&& in
(select c.&&Id&& from &&SalePersonPermission&& c
join &&SalePersonPermissionDel&& ct on ct.&&SaleId&&=c.&&Id&&
where ct.&&SaleId&&=c.&&Id&&);

delete from &&SalePersonPermission&&  where &&InheritedFromNumber&& <= 0;


   insert into &&RelationshipPersonPermDel&& (&&RelationshipId&&,&&PermissionId&&,&&Relationship&&,&&InheritedFromNumber&&,&&UserSecuritySetCacheId&&,&&PermissionRole&&)
   select c.&&Id&& as RelationshipId,c.&&PermissionId&&,&&Relationship&&,c.&&InheritedFromNumber&&,c.&&UserSecuritySetCacheId&&,c.&&PermissionRole&&
   from &&RelationshipPersonPermission&& c
      left join &&Relationship&& r on r.&&Contractor&&=$3 and c.&&Relationship&&=r.&&Id&&
      where c.&&PermissionId&&=v_PermissionRelationshipId and c.&&UserSecuritySetCacheId&&=$2 and r.&&Contractor&&=$3
        and r.&&InheritPermissions&&=1
        and c.&&PermissionRole&&=$4
        and c.&&InheritedFromNumber&& > 0;


			/*Удалить пермишены реальных пользователей для исполнителей*/
	insert into &&RelationshipPersonPermDel&& (&&RelationshipId&&, &&PermissionId&&, &&UserSecuritySetCacheId&&, &&Relationship&&	)
	select  &&Id&&,c.&&PermissionId&&,c.&&UserSecuritySetCacheId&&,&&Relationship&&
	from &&RelationshipPersonPermission&& c
	where 
		&&InheritedFromNumber&& > 0
		and &&User&&!=v_adminUser and
		c.&&PermissionRole&& =v_PermissionRoleTypeParticipantWork
		and exists (
			select t.&&RelationshipId&& from &&RelationshipPersonPermDel&& t where 
				t.&&PermissionRole&& =v_PermissionRoleTypeParticipantWork
				and c.&&PermissionId&&=t.&&permissionId&&
				and c.&&Relationship&&=t.&&Relationship&& );

/*Удалить пермишены реальных пользователей для исполнителей*/
	insert into &&RelationshipPersonPermDel&& (&&RelationshipId&&, &&PermissionId&&, &&UserSecuritySetCacheId&&, &&Relationship&&)
	select &&Id&&,c.&&PermissionId&&,c.&&UserSecuritySetCacheId&&,&&Relationship&&
	from &&RelationshipPersonPermission&& c
	where 
		&&InheritedFromNumber&& > 0
		and &&User&&!=v_adminUser 
		and c.&&PermissionRole&& =v_PermissionRoleTypeInforms
		and exists (
			select t.&&RelationshipId&& from &&RelationshipPersonPermDel&& t where 
				t.&&PermissionRole&& =v_PermissionRoleTypeInforms
				and c.&&PermissionId&&=t.&&permissionId&&
				and c.&&Relationship&&=t.&&Relationship&& );

  update &&RelationshipPersonPermission&& set &&InheritedFromNumber&&=&&InheritedFromNumber&&-1
  where &&Id&& in  (select c.&&Id&&
  from &&RelationshipPersonPermission&& c
  join &&RelationshipPersonPermDel&& ct on ct.&&RelationshipId&&=c.&&Id&&
  where  ct.&&RelationshipId&&=c.&&Id&&);

-- Грохнуть пустые
        delete from &&RelationshipPersonPermission&&  where &&InheritedFromNumber&&<=0;



end

$$
language plpgsql;

CREATE OR REPLACE FUNCTION CheckPermWhenDelCategories(CategoryId bigint, &&ContractorId&& bigint) RETURNS void
AS $$
DECLARE
v_AdminUid uuid; v_AdminUser bigint; v_UserMask bigint;
v_CRMContractorCreateElementPermissionId uuid; v_CRMContractorIssuancePermissionId uuid; v_ViewContractorPermissionId uuid; v_EditContractorPermissionId uuid; v_CRMContractorFullAccessPermissionId uuid;
v_CRMContactCreateElementPermissionId uuid; v_CRMContactIssuancePermissionId uuid; v_ViewContactPermissionId uuid; v_EditContactPermissionId uuid; v_CRMContactFullAccessPermissionId uuid;
v_CRMRelationshipCreateElementPermissionId uuid; v_CRMRelationshipIssuanceElementPermissionId uuid; v_ViewRelationshipPermissionId uuid; v_EditRelationshipPermissionId uuid; v_CRMRelationshipFullAccessPermissionId uuid;
v_CRMSaleCreateElementPermissionId uuid; v_CRMSaleIssuancePermissionId uuid; v_ViewSalePermissionId uuid; v_EditSalePermissionId uuid; v_CRMSaleFullAccessPermissionId uuid;
v_PermissionRoleTypeParticipantWork uuid; v_PermissionRoleAuthor uuid; v_PermissionRoleTypeInforms uuid; v_PermissionRoleTypeResponsible uuid;
BEGIN
v_AdminUid = 'F0E949BF-4DA4-4C02-B04C-CA61964B4FE8'; v_UserMask = 72057594037927936; -- побитовый сдвиг влево 1 на 56 разрядов (2 ^ 56) 1055
v_CRMContractorCreateElementPermissionId = '44ED88D4-A466-4fed-B194-B8288560CB48'; v_CRMContractorIssuancePermissionId = '1CD25727-7CE6-443c-84BD-7975822C79E6'; v_ViewContractorPermissionId = '9219C9AB-7E68-47B1-8939-FF6FC4439DA0'; v_EditContractorPermissionId = '8C932B94-2F9C-488E-A36F-949A11C9741E'; v_CRMContractorFullAccessPermissionId = 'E612615C-D5E2-4c4b-9DF0-B4D9EEB983A5';
v_CRMContactCreateElementPermissionId = 'BCE45C2C-CAE1-41df-8A0A-C54E0409E8B5'; v_CRMContactIssuancePermissionId = '05D9000F-0600-49a6-8AE8-DA1DA72BFCF1'; v_ViewContactPermissionId = '3626682F-B657-419E-9A8E-392C14ABE455'; v_EditContactPermissionId = 'ABC752AD-3623-4F14-A47F-121999890D2C'; v_CRMContactFullAccessPermissionId = '76B481D5-2E07-4417-9098-A57DE879FA56';
v_CRMRelationshipCreateElementPermissionId = 'BA5E9414-B347-4eaa-A019-14D4FA02F5E2'; v_ViewRelationshipPermissionId = '186D4CC4-6924-4848-93AC-6D8DE389CB08'; v_EditRelationshipPermissionId = '0B980531-D097-4EC1-8616-56E6AB15770E'; v_CRMRelationshipIssuanceElementPermissionId = '679876A7-8882-43d4-8FC2-3E7C9DB58ADB'; v_CRMRelationshipFullAccessPermissionId = '38A0AC5D-8D9C-4BB5-BDBA-A0E6CFD43C30';
v_CRMSaleIssuancePermissionId = 'F2141650-BB6D-4e3a-BB62-C0F071CF8EEA'; v_ViewSalePermissionId = 'AAE16346-B0E6-4949-ACAB-0914C573DE55'; v_EditSalePermissionId = 'AF2CEF4B-F639-49B4-BD88-363F20BD5A74'; v_CRMSaleCreateElementPermissionId = '7DB77821-D6D3-4dd2-AD1B-798330506ADC'; v_CRMSaleFullAccessPermissionId = 'DB60BB49-0DE1-46ee-8CE8-DCD59DB93351';
v_PermissionRoleTypeParticipantWork = '9A945D2E-BCFA-4AF4-8653-9A67A5ED6386'; v_PermissionRoleAuthor = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92'; v_PermissionRoleTypeInforms = '21888C0C-8BCA-4B26-AF13-4C497EECCED6'; v_PermissionRoleTypeResponsible = 'CE4D6154-E36E-406b-8BE9-25266C5BDD15';
SELECT u.&&Id&& FROM &&User&& u WHERE u.&&Uid&& = v_AdminUid INTO v_AdminUser;
DROP TABLE IF EXISTS &&TemplateContractorPermissionDel&&; CREATE TEMP TABLE &&TemplateContractorPermissionDel&& ON COMMIT DROP AS SELECT t.* FROM &&TemplateContractorPermission&& t JOIN &&Category&& c ON c.&&ContainerContractorPermissio&& = t.&&ContainerContractor&& WHERE c.&&Id&& = $1;
-- Забрать привилегию из контрагента INSERT INTO &&ContractorPersonPermissionDel&& (&&ContractorId&&, &&PermissionId&&, &&User&&, &&Group&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Contractor&&, &&UserSecuritySetCacheId&&, &&OrganizationItemPosition&&, &&Child&& ) SELECT c.&&Id&& AS &&ContractorId&&, t.&&PermissionId&&, t.&&User&&, t.&&Group&&, t.&&PermissionRole&&, t.&&OrganizationItemEmployee&&, &&Contractor&&, CASE c.&&PermissionRole&& WHEN v_PermissionRoleAuthor THEN (SELECT &&CreationAuthor&& FROM &&Contractor&& AS con WHERE con.&&Id&& = c.&&Contractor&&) | v_UserMask WHEN v_PermissionRoleTypeResponsible THEN (SELECT &&Responsible&& FROM &&Contractor&& AS con WHERE con.&&Id&& = c.&&Contractor&&) | v_UserMask ELSE t.&&UserSecuritySetCacheId&& END AS &&UserSecuritySetCacheId&&, t.&&OrganizationItemPosition&&, COUNT(1) AS &&Child&& FROM &&ContractorPersonPermission&& c LEFT JOIN &&TemplateContractorPermissionDel&& t ON c.&&PermissionId&& = t.&&PermissionId&& AND t.&&PermissionRole&& = c.&&PermissionRole&& AND c.&&UserSecuritySetCacheId&& = CASE c.&&PermissionRole&& WHEN v_PermissionRoleAuthor THEN (SELECT &&CreationAuthor&& | v_UserMask FROM &&Contractor&& AS con WHERE con.&&Id&& = c.&&Contractor&&) WHEN v_PermissionRoleTypeResponsible THEN (SELECT &&Responsible&& | v_UserMask FROM &&Contractor&& AS con WHERE con.&&Id&& = c.&&Contractor&&) ELSE t.&&UserSecuritySetCacheId&& END WHERE c.&&InheritedFromNumber&& > 0 AND t.&&Id&& IS NOT NULL AND c.&&Contractor&& = $2 GROUP BY c.&&Id&&, t.&&PermissionId&&, t.&&User&&, t.&&Group&&, t.&&PermissionRole&&, t.&&OrganizationItemEmployee&&, &&Contractor&&, t.&&UserSecuritySetCacheId&&, t.&&OrganizationItemPosition&&;
-- Удалить пермишены реальных пользователей для исполнителей INSERT INTO &&ContractorPersonPermissionDel&& (&&ContractorId&&, &&PermissionId&&, &&User&&, &&Group&&, &&OrganizationItemPosition&&, &&UserSecuritySetCacheId&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Contractor&&, &&Child&& ) SELECT &&Id&&, &&PermissionId&&, &&User&&, &&Group&&, &&OrganizationItemPosition&&, &&UserSecuritySetCacheId&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Contractor&&, (SELECT COUNT(1) FROM &&TemplateContractorPermissionDel&& AS t WHERE c.&&PermissionId&& = t.&&PermissionId&& AND c.&&PermissionRole&& = t.&&PermissionRole&& AND &&User&& = v_AdminUser) FROM &&ContractorPersonPermission&& c WHERE &&InheritedFromNumber&& > 0 AND &&User&& != v_AdminUser AND &&PermissionRole&& = v_PermissionRoleTypeParticipantWork AND EXISTS(SELECT t.&&ContractorId&& FROM &&ContractorPersonPermissionDel&& t WHERE &&PermissionRole&& = v_PermissionRoleTypeParticipantWork AND c.&&PermissionId&& = t.&&PermissionId&& AND c.&&Contractor&& = t.&&Contractor&& );
-- Удалить пермишены реальных пользователей для исполнителей INSERT INTO &&ContractorPersonPermissionDel&& (&&ContractorId&&, &&PermissionId&&, &&User&&, &&Group&&, &&OrganizationItemPosition&&, &&UserSecuritySetCacheId&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Contractor&&, &&Child&& ) SELECT &&Id&&, &&PermissionId&&, &&User&&, &&Group&&, &&OrganizationItemPosition&&, &&UserSecuritySetCacheId&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Contractor&&, (SELECT COUNT(1) FROM &&TemplateContractorPermissionDel&& AS t WHERE c.&&PermissionId&& = t.&&PermissionId&& AND c.&&PermissionRole&& = t.&&PermissionRole&& AND &&User&& = v_AdminUser) FROM &&ContractorPersonPermission&& c WHERE &&InheritedFromNumber&& > 0 AND &&User&& != v_AdminUser AND &&PermissionRole&& = v_PermissionRoleTypeInforms AND EXISTS(SELECT t.&&ContractorId&& FROM &&ContractorPersonPermissionDel&& t WHERE &&PermissionRole&& = v_PermissionRoleTypeInforms AND c.&&PermissionId&& = t.&&PermissionId&& AND c.&&Contractor&& = t.&&Contractor&& );
-- Перезаписать реальных пользователей в ответственных UPDATE &&ContractorPersonPermissionDel&& SET &&User&& = (SELECT &&Responsible&& FROM &&Contractor&& con WHERE con.&&Id&& = &&Contractor&&), &&UserSecuritySetCacheId&& = (SELECT &&Responsible&& | v_UserMask FROM &&Contractor&& con WHERE con.&&Id&& = &&Contractor&&) WHERE &&PermissionRole&& = v_PermissionRoleTypeResponsible;
UPDATE &&ContractorPersonPermission&& c SET &&InheritedFromNumber&& = &&InheritedFromNumber&& - (SELECT MAX(ct.&&Child&&) FROM &&ContractorPersonPermissionDel&& ct WHERE ct.&&ContractorId&& = c.&&Id&&) WHERE &&Id&& IN (SELECT c.&&Id&& FROM &&ContractorPersonPermission&& c JOIN &&ContractorPersonPermissionDel&& ct ON ct.&&ContractorId&& = c.&&Id&& WHERE ct.&&ContractorId&& = c.&&Id&&);
-- Забрать привилегию из контактов INSERT INTO ContactPersonPermissionDel (&&ContactId&&, &&PermissionId&&, &&User&&, &&Group&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Contact&&, &&UserSecuritySetCacheId&&, &&InheritedFromNumber&&, &&OrganizationItemPosition&& ) SELECT c.&&Id&& AS &&ContactId&&, c.&&PermissionId&&, t.&&User&&, t.&&Group&&, t.&&PermissionRole&&, t.&&OrganizationItemEmployee&&, &&Contact&&, t.&&UserSecuritySetCacheId&&, c.&&InheritedFromNumber&&, t.&&OrganizationItemPosition&& FROM &&ContactPersonPermission&& c LEFT JOIN &&ContractorPersonPermissionDel&& t ON c.&&PermissionId&& = CASE WHEN t.&&PermissionId&& = v_CRMContractorCreateElementPermissionId THEN v_CRMContactCreateElementPermissionId WHEN t.&&PermissionId&& = v_CRMContractorIssuancePermissionId THEN v_CRMContactIssuancePermissionId WHEN t.&&PermissionId&& = v_ViewContractorPermissionId THEN v_ViewContactPermissionId WHEN t.&&PermissionId&& = v_EditContractorPermissionId THEN v_EditContactPermissionId WHEN t.&&PermissionId&& = v_CRMContractorFullAccessPermissionId THEN v_CRMContactFullAccessPermissionId ELSE t.&&PermissionId&& END AND c.&&UserSecuritySetCacheId&& = CASE c.&&PermissionRole&& WHEN v_PermissionRoleAuthor THEN (SELECT &&CreationAuthor&& | v_UserMask FROM &&Contact&& AS con WHERE con.&&Id&& = c.&&Contact&&) WHEN v_PermissionRoleTypeResponsible THEN (SELECT contr.&&Responsible&& | v_UserMask FROM &&Contact&& AS con LEFT JOIN &&Contractor&& AS contr ON contr.&&Id&& = con.&&Contractor&& WHERE con.&&Id&& = &&Contact&&) ELSE t.&&UserSecuritySetCacheId&& END AND t.&&PermissionRole&& = c.&&PermissionRole&& LEFT JOIN &&Contact&& ca ON c.&&Contact&& = ca.&&Id&& AND ca.&&InheritPermissions&& = 1 LEFT JOIN &&ContractorPersonPermission&& cc ON cc.&&Id&& = t.&&ContractorId&& WHERE c.&&InheritedFromNumber&& > 0 AND t.&&ContractorId&& IS NOT NULL AND ca.&&Contractor&& = t.&&Contractor&& AND cc.&&InheritedFromNumber&& <= 0;
UPDATE &&ContactPersonPermission&& SET &&InheritedFromNumber&& = &&InheritedFromNumber&& - 1 WHERE &&Id&& IN (SELECT c.&&Id&& FROM &&ContactPersonPermission&& c JOIN ContactPersonPermissionDel ct ON ct.&&ContactId&& = c.&&Id&& WHERE ct.&&ContactId&& = c.&&Id&&);
-- Грохнуть пустые контакты DELETE FROM &&ContactPersonPermission&& WHERE &&InheritedFromNumber&& = 0;
-- Забрать привилегию из Сделок INSERT INTO &&SalePersonPermissionDel&& (&&SaleId&&, &&PermissionId&&, &&User&&, &&Group&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Sale&&, &&UserSecuritySetCacheId&&, &&InheritedFromNumber&&, &&OrganizationItemPosition&& ) SELECT c.&&Id&& AS &&SaleId&&, c.&&PermissionId&&, t.&&User&&, t.&&Group&&, t.&&PermissionRole&&, t.&&OrganizationItemEmployee&&, &&Sale&&, t.&&UserSecuritySetCacheId&&, c.&&InheritedFromNumber&&, t.&&OrganizationItemPosition&& FROM &&SalePersonPermission&& c LEFT JOIN &&ContractorPersonPermissionDel&& t ON c.&&PermissionId&& = CASE WHEN t.&&PermissionId&& = v_CRMContractorCreateElementPermissionId THEN v_CRMSaleCreateElementPermissionId WHEN t.&&PermissionId&& = v_CRMContractorIssuancePermissionId THEN v_CRMSaleIssuancePermissionId WHEN t.&&PermissionId&& = v_ViewContractorPermissionId THEN v_ViewSalePermissionId WHEN t.&&PermissionId&& = v_EditContractorPermissionId THEN v_EditSalePermissionId WHEN t.&&PermissionId&& = v_CRMContractorFullAccessPermissionId THEN v_CRMSaleFullAccessPermissionId ELSE t.&&PermissionId&& END AND c.&&UserSecuritySetCacheId&& = CASE c.&&PermissionRole&& WHEN v_PermissionRoleAuthor THEN (SELECT &&Author&& | v_UserMask FROM &&Sale&& AS con WHERE con.&&Id&& = c.&&Sale&&) WHEN v_PermissionRoleTypeResponsible THEN (SELECT &&Responsible&& | v_UserMask FROM &&Sale&& AS con WHERE con.&&Id&& = c.&&Sale&&) ELSE t.&&UserSecuritySetCacheId&& END AND t.&&PermissionRole&& = c.&&PermissionRole&& LEFT JOIN &&Sale&& AS ca ON c.&&Sale&& = ca.&&Id&& AND ca.&&InheritPermissions&& = 1 LEFT JOIN &&ContractorPersonPermission&& AS cc ON cc.&&Id&& = t.&&ContractorId&& WHERE c.&&InheritedFromNumber&& > 0 AND t.&&ContractorId&& IS NOT NULL AND ca.&&Contractor&& = t.&&Contractor&& AND cc.&&InheritedFromNumber&& <= 0;
UPDATE &&SalePersonPermission&& SET &&InheritedFromNumber&& = &&InheritedFromNumber&& - 1 WHERE &&Id&& IN (SELECT c.&&Id&& FROM &&SalePersonPermission&& c JOIN &&SalePersonPermissionDel&& ct ON ct.&&SaleId&& = c.&&Id&& WHERE ct.&&SaleId&& = c.&&Id&&);
-- Грохнуть пустые привилегии сделок DELETE FROM &&SalePersonPermission&& WHERE &&InheritedFromNumber&& = 0;
-- работаем с взаимоотношениями -- Забрать привилегию у взаимоотношения из контрагента INSERT INTO &&RelationshipPersonPermDel&& (&&RelationshipId&&, &&PermissionId&&, &&User&&, &&Group&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Relationship&&, &&UserSecuritySetCacheId&&, &&OrganizationItemPosition&& ) SELECT c.&&Id&& AS &&RelationshipId&&, c.&&PermissionId&&, c.&&User&&, c.&&Group&&, c.&&PermissionRole&&, c.&&OrganizationItemEmployee&&, &&Relationship&&, c.&&UserSecuritySetCacheId&&, c.&&OrganizationItemPosition&& FROM &&RelationshipPersonPermission&& AS c WHERE c.&&InheritedFromNumber&& > 0 AND c.&&Relationship&& IN (SELECT r.&&Id&& FROM &&Relationship&& AS r WHERE r.&&Contractor&& IS NOT NULL) AND EXISTS(SELECT 1 FROM &&ContractorPersonPermissionDel&& AS t LEFT JOIN &&Relationship&& AS ca ON c.&&Relationship&& = ca.&&Id&& AND ca.&&InheritPermissions&& = 1 LEFT JOIN &&ContractorPersonPermission&& AS cc ON cc.&&Id&& = t.&&ContractorId&& WHERE CASE WHEN t.&&PermissionId&& = v_CRMContractorCreateElementPermissionId THEN v_CRMRelationshipCreateElementPermissionId WHEN t.&&PermissionId&& = v_CRMContractorIssuancePermissionId THEN v_CRMRelationshipIssuanceElementPermissionId WHEN t.&&PermissionId&& = v_ViewContractorPermissionId THEN v_ViewRelationshipPermissionId WHEN t.&&PermissionId&& = v_EditContractorPermissionId THEN v_EditRelationshipPermissionId WHEN t.&&PermissionId&& = v_CRMContractorFullAccessPermissionId THEN v_CRMRelationshipFullAccessPermissionId ELSE t.&&PermissionId&& END = c.&&PermissionId&& AND c.&&UserSecuritySetCacheId&& = CASE c.&&PermissionRole&& WHEN v_PermissionRoleAuthor THEN (SELECT &&CreationAuthor&& | v_UserMask FROM &&Relationship&& AS con WHERE con.&&Id&& = c.&&Relationship&&) WHEN v_PermissionRoleTypeResponsible THEN (SELECT &&Relationship&& | v_UserMask FROM &&Relationship&& AS con WHERE con.&&Id&& = &&Relationship&&) ELSE t.&&UserSecuritySetCacheId&& END AND c.&&PermissionRole&& = t.&&PermissionRole&& AND ca.&&Contractor&& = t.&&Contractor&& AND cc.&&InheritedFromNumber&& <= 0 ); -- Удалить пермишены реальных пользователей для исполнителей INSERT INTO &&RelationshipPersonPermDel&& (&&RelationshipId&&, &&PermissionId&&, &&User&&, &&Group&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Relationship&&, &&UserSecuritySetCacheId&&, &&OrganizationItemPosition&& ) SELECT c.&&Id&& AS &&RelationshipId&&, c.&&PermissionId&&, c.&&User&&, c.&&Group&&, c.&&PermissionRole&&, c.&&OrganizationItemEmployee&&, &&Relationship&&, c.&&UserSecuritySetCacheId&&, c.&&OrganizationItemPosition&& FROM &&RelationshipPersonPermission&& AS c WHERE c.&&InheritedFromNumber&& > 0 AND c.&&User&& != v_AdminUser AND c.&&PermissionRole&& = v_PermissionRoleTypeParticipantWork AND EXISTS(SELECT &&RelationshipId&& FROM &&RelationshipPersonPermDel&& AS t WHERE &&PermissionRole&& = v_PermissionRoleTypeParticipantWork AND c.&&PermissionId&& = t.&&PermissionId&& AND c.&&Relationship&& = t.&&Relationship&& );
-- Удалить пермишены реальных пользователей для исполнителей INSERT INTO &&RelationshipPersonPermDel&& (&&RelationshipId&&, &&PermissionId&&, &&User&&, &&Group&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Relationship&&, &&UserSecuritySetCacheId&&, &&OrganizationItemPosition&& ) SELECT c.&&Id&& AS &&RelationshipId&&, c.&&PermissionId&&, c.&&User&&, c.&&Group&&, c.&&PermissionRole&&, c.&&OrganizationItemEmployee&&, &&Relationship&&, c.&&UserSecuritySetCacheId&&, c.&&OrganizationItemPosition&& FROM &&RelationshipPersonPermission&& AS c WHERE c.&&InheritedFromNumber&& > 0 AND c.&&User&& != v_AdminUser AND c.&&PermissionRole&& = v_PermissionRoleTypeParticipantWork AND EXISTS(SELECT &&RelationshipId&& FROM &&RelationshipPersonPermDel&& AS t WHERE &&PermissionRole&& = v_PermissionRoleTypeInforms AND c.&&PermissionId&& = t.&&PermissionId&& AND c.&&Relationship&& = t.&&Relationship&& );
UPDATE &&RelationshipPersonPermission&& SET &&InheritedFromNumber&& = &&InheritedFromNumber&& - 1 WHERE &&Id&& IN (SELECT c.&&Id&& FROM &&SalePersonPermission&& c JOIN &&RelationshipPersonPermDel&& ct ON ct.&&RelationshipId&& = c.&&Id&& WHERE ct.&&RelationshipId&& = c.&&Id&& AND ct.&&UserSecuritySetCacheId&& = c.&&UserSecuritySetCacheId&& AND ct.&&PermissionRole&& = c.&&PermissionRole&&);
DELETE FROM &&RelationshipPersonPermission&& WHERE &&InheritedFromNumber&& <= 0;
-- Грохнуть пустые пермишены в контрагенте DELETE FROM &&ContractorPersonPermission&& WHERE &&InheritedFromNumber&& <= 0;
END
$$ LANGUAGE plpgsql;


      create or replace function UpdateCategoryPermissions()
returns void

as
$$

declare

v_PermissionRoleTypeResponsible uuid;
v_PermissionRoleTypeParticipantWork uuid;
v_AdminUid  uuid;
v_AdminUser bigint;
v_PermissionRoleTypeInforms uuid;
v_PermissionRoleAuthor uuid;

v_CRMContractorCreateElementPermissionId uuid;
v_CRMContractorIssuancePermissionId uuid;
v_ViewContractorPermissionId uuid;
v_EditContractorPermissionId uuid;
v_FullContractorPermissionId uuid;


v_CRMSaleIssuancePermissionId uuid;
v_ViewSalePermissionId uuid;
v_EditSalePermissionId uuid;
v_CRMSaleCreateElementPermissionId uuid ;
v_FullSalePermissionId uuid;

v_CRMContactCreateElementPermissionId uuid;
