v_PermissionRoleTypeResp uuid;
v_UserMask bigint;
  v_defaultCategory bigint;
  v_defaultTemplLeadCategory bigint;
  v_defaultTemplCategory bigint;

begin

v_PermissionRoleTypeResponsible  = 'CE4D6154-E36E-406b-8BE9-25266C5BDD15';
v_PermissionRoleTypeInforms = '21888C0C-8BCA-4B26-AF13-4C497EECCED6';
v_PermissionRoleTypeParticipantWork  = '9A945D2E-BCFA-4AF4-8653-9A67A5ED6386';
v_AdminUid='f0e949bf-4da4-4c02-b04c-ca61964b4fe8';
v_PermissionRoleAuthor='B4565CC1-7CB3-4201-B7BD-15872D1E7F92';

v_PermissionRoleTypeResp = 'CE4D6154-E36E-406b-8BE9-25266C5BDD15';  
v_UserMask = 72057594037927936; -- побитовый сдвиг влево 1 на 56 разрядов (2 ^ 56) 1055

v_CRMContractorCreateElementPermissionId = '44ED88D4-A466-4fed-B194-B8288560CB48';
v_CRMContractorIssuancePermissionId = '1CD25727-7CE6-443c-84BD-7975822C79E6';
v_ViewContractorPermissionId = '9219C9AB-7E68-47B1-8939-FF6FC4439DA0';
v_EditContractorPermissionId = '8C932B94-2F9C-488E-A36F-949A11C9741E';
v_FullContractorPermissionId = 'E612615C-D5E2-4c4b-9DF0-B4D9EEB983A5';


v_CRMSaleIssuancePermissionId = 'F2141650-BB6D-4e3a-BB62-C0F071CF8EEA';
v_ViewSalePermissionId = 'AAE16346-B0E6-4949-ACAB-0914C573DE55';
v_EditSalePermissionId = 'AF2CEF4B-F639-49B4-BD88-363F20BD5A74';
v_CRMSaleCreateElementPermissionId = '7DB77821-D6D3-4dd2-AD1B-798330506ADC';
v_FullSalePermissionId = 'DB60BB49-0DE1-46ee-8CE8-DCD59DB93351';

v_CRMContactCreateElementPermissionId = 'BCE45C2C-CAE1-41df-8A0A-C54E0409E8B5';
v_CRMContactIssuancePermissionId = '05D9000F-0600-49a6-8AE8-DA1DA72BFCF1';
v_ViewContactPermissionId = '3626682F-B657-419E-9A8E-392C14ABE455';
v_EditContactPermissionId = 'ABC752AD-3623-4F14-A47F-121999890D2C';
v_CRMContactFullAccessPermissionId = '76B481D5-2E07-4417-9098-A57DE879FA56';

v_CRMInpaymentCreateElementPermissionId = 'D130BB5F-6A26-4e37-B62C-F3B443E3BF53';
v_ViewInpaymentPermissionId  = '837FF0F3-03A7-4A17-86EA-A72B3AB4886B';
v_EditInpaymentPermissionId  = 'E23802D7-F3B5-431E-A72E-7133C3C9343F';
v_CRMInpaymentIssuanceElementPermissionId  = 'ACF5606C-B566-426b-BAEC-E74061095BEB';
v_CRMInpaymentFullAccessPermissionId  = 'A27A46F9-BCD8-4e82-AE49-E58675DE52D7';


v_CRMRelationshipCreateElementPermissionId = 'BA5E9414-B347-4eaa-A019-14D4FA02F5E2';
v_ViewRelationshipPermissionId = '186D4CC4-6924-4848-93AC-6D8DE389CB08';
v_EditRelationshipPermissionId  = '0B980531-D097-4EC1-8616-56E6AB15770E';
v_CRMRelationshipIssuanceElementPermissionId  = '679876A7-8882-43d4-8FC2-3E7C9DB58ADB';
v_CRMRelationshipFullAccessPermissionId = '38A0AC5D-8D9C-4BB5-BDBA-A0E6CFD43C30';

v_ViewLeadPermissionId ='C660E4B4-03BF-4315-9600-5086E47653B4';
v_EditLeadPermissionId ='AE298CD3-A16A-4B55-ACFC-545E4A0EBD48';
v_CRMLeadCreateElementPermissionId ='643FE44B-8192-4615-B853-106CD6F09EDE';
v_CRMLeadFullAccessPermissionId ='90BE803C-7857-4F2D-A8B4-129264504101';
v_CRMLeadIssuanceElementPermissionId ='E70A9AD1-80B2-4435-80E9-EF8E14B974CE';

select ca.&&Id&&, &&ContainerContractorPermissio&&, &&ContainerLeadPermission&& from &&Category&& ca where &&Uid&&='B53287AB-211B-4498-A054-2776C4D270AD'
into v_defaultCategory,v_defaultTemplCategory,v_defaultTemplLeadCategory;

delete from &&CheckContractorCategTmp&&;
delete from &&ContractorPersonPermissionDel&&;
delete from &&ContractorPersonPermissionUpd&&;
delete from &&ContactPersonPermissionDel&&;
delete from &&ContactPersonPermissionUpd&&;
delete from &&SalePersonPermissionDel&&;
delete from &&SalePersonPermissionUpd&&;
delete from &&LeadPersonPermissionDel&&;
delete from &&LeadPersonPermissionUpd&&;
delete from &&ContractorPersonPermTmp&&;
delete from &&RelationshipPersPermTmp&&;
delete from &&RelationshipPersonPermUpd&&;

select u.&&Id&& from &&User&& u where u.&&Uid&& = v_AdminUid 
        into v_AdminUser;



insert into &&ContractorPersonPermTmp&&
      (&&Id&&
      ,&&Uid&&
      ,&&PermissionId&&
      ,&&User&&
      ,&&Group&&
      ,&&OrganizationItemPosition&&
      ,&&UserSecuritySetCacheId&&
      ,&&PermissionRole&&
      ,&&OrganizationItemEmployee&&
      ,&&Contractor&&
      ,&&InheritedFromNumber&&)

      select &&Id&&,
Uid
,&&PermissionId&&
,&&User&&
,&&Group&&
,&&OrganizationItemPosition&&
,&&UserSecuritySetCacheId&&
,&&PermissionRole&&
,&&OrganizationItemEmployee&&
,&&Contractor&&
,&&InheritedFromNumber&& from &&ContractorPersonPermission&& 
where &&User&& is not null or &&Group&& is not null or &&OrganizationItemPosition&& is not null or &&OrganizationItemEmployee&& is not null;

/*Забрать привилегию из контрагента*/

  insert into &&ContractorPersonPermissionDel&&(&&ContractorId&&,&&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&, &&OrganizationItemEmployee&&,&&Contractor&&,&&UserSecuritySetCacheId&&,&&OrganizationItemPosition&&, &&Child&&)    
  select c.&&Id&& as &&ContractorId&&,c.&&PermissionId&&,c.&&User&&,c.&&Group&&,c.&&PermissionRole&&,c.&&OrganizationItemEmployee&&,&&Contractor&&,c.&&UserSecuritySetCacheId&&,c.&&OrganizationItemPosition&&
  ,(select count(1) from &&TemplateContractorPermission&& t where t.&&DelPermission&& is not null and t.&&DelPermission&& = 1 and c.&&PermissionId&&=t.&&PermissionId&& 
  and t.&&UserSecuritySetCacheId&&=
  case c.&&PermissionRole&& 
	    when v_PermissionRoleAuthor then  (v_adminUser|v_UserMask)
	    when v_PermissionRoleTypeResponsible then  (v_adminUser|v_UserMask)
    ELSE c.&&UserSecuritySetCacheId&&
    end
    and c.&&PermissionRole&&=t.&&PermissionRole&&)
  from &&ContractorPersonPermTmp&& c
  where c.&&InheritedFromNumber&& > 0
  and
  exists (select 1 from &&TemplateContractorPermission&& t where t.&&DelPermission&& is not null and t.&&DelPermission&& = 1 and c.&&PermissionId&&=t.&&PermissionId&& and 
  t.&&UserSecuritySetCacheId&&
  =   case c.&&PermissionRole&& 
	      when v_PermissionRoleAuthor then  (v_adminUser|v_UserMask)
	      when v_PermissionRoleTypeResponsible then  (v_adminUser|v_UserMask)
        ELSE c.&&UserSecuritySetCacheId&&
      end
      and c.&&PermissionRole&&=t.&&PermissionRole&&

  );

/*Удалить пермишены реальных пользователей для исполнителей*/
	insert into &&ContractorPersonPermissionDel&& (&&ContractorId&&,&&PermissionId&&,&&User&&,&&Group&&,&&OrganizationItemPosition&&,&&UserSecuritySetCacheId&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Contractor&&,&&Child&&)
	select &&Id&&,&&PermissionId&&,&&User&&,&&Group&&,&&OrganizationItemPosition&&,&&UserSecuritySetCacheId&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Contractor&&
		  ,(select count(1) from &&TemplateContractorPermission&& t where delpermission is not null and delpermission = 1 and c.&&PermissionId&&=t.&&permissionId&& and c.&&PermissionRole&&=t.&&PermissionRole&& and &&User&&=v_adminUser)
	from &&ContractorPersonPermTmp&& c
	where 
		&&InheritedFromNumber&& > 0
		and &&User&&!=v_adminUser and
		&&PermissionRole&& =v_PermissionRoleTypeParticipantWork
		and exists (
			select &&ContractorId&& from &&ContractorPersonPermissionDel&& t where 
				&&PermissionRole&& =v_PermissionRoleTypeParticipantWork
				and c.&&PermissionId&&=t.&&permissionId&&
				and c.&&Contractor&&=t.&&Contractor&& );

/*Удалить пермишены реальных пользователей для исполнителей*/
	insert into &&ContractorPersonPermissionDel&& (&&ContractorId&&,&&PermissionId&&,&&User&&,&&Group&&,&&OrganizationItemPosition&&,&&UserSecuritySetCacheId&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Contractor&&,&&Child&&)
	select &&Id&&,&&PermissionId&&,&&User&&,&&Group&&,&&OrganizationItemPosition&&,&&UserSecuritySetCacheId&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Contractor&&
		  ,(select count(1) from &&TemplateContractorPermission&& t where &&delpermission&& is not null and &&delpermission&& = 1 and c.&&PermissionId&&=t.&&permissionId&& and c.&&PermissionRole&&=t.&&PermissionRole&& and &&User&&=v_adminUser)
	from &&ContractorPersonPermTmp&& c
	where 
		&&InheritedFromNumber&& > 0
		and &&User&&!=v_adminUser 
		and &&PermissionRole&& =v_PermissionRoleTypeInforms
		and exists (
			select &&ContractorId&& from &&ContractorPersonPermissionDel&& t where 
				&&PermissionRole&& =v_PermissionRoleTypeInforms
				and c.&&PermissionId&&=t.&&permissionId&&
				and c.&&Contractor&&=t.&&Contractor&& );



update &&ContractorPersonPermTmp&& c set &&InheritedFromNumber&& = c.&&InheritedFromNumber&& - (select max(ct.&&Child&&) from &&ContractorPersonPermissionDel&& ct where c.&&Id&&=ct.&&ContractorId&&)
where c.&&Id&& in (select ct.&&ContractorId&& from &&ContractorPersonPermissionDel&& ct);

  insert into &&CheckContractorCategTmp&& (&&Id&&)  select &&Contractor&& from &&ContractorPersonPermissionDel&&;

delete from &&ContractorPersonPermissionDel&&;

insert into &&ContractorPersonPermissionDel&&(&&ContractorId&&,&&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Contractor&&,&&UserSecuritySetCacheId&&,&&OrganizationItemPosition&&,&&Child&&,&&InheritedFromNumber&&)
select &&Id&& ContractorId,&&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Contractor&&,&&UserSecuritySetCacheId&&,&&OrganizationItemPosition&&,1,&&InheritedFromNumber&& 
from &&ContractorPersonPermTmp&& where &&InheritedFromNumber&&<=0;


delete from &&ContractorPersonPermTmp&& where &&InheritedFromNumber&& <= 0;

insert into &&ContractorPersonPermissionUpd&& (&&Id&&,&&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Contractor&&,&&UserSecuritySetCacheId&&,&&OrganizationItemPosition&&,&&Ins&&,&&Child&&)
select - 1 as &&Id&&,c.&&PermissionId&&,c.&&User&&,c.&&Group&&,c.&&PermissionRole&&,c.&&OrganizationItemEmployee&&,c.&&Contractor&& as &&Contractor&&,c.&&UserSecuritySetCacheId&&,c.&&OrganizationItemPosition&&,0 &&Ins&&,
(select count(1) from &&TemplateContractorPermission&& t where &&AddPermission&& = 1 and &&DelPermission&&!=1 and c.&&PermissionId&&=t.&&PermissionId&& and c.&&UserSecuritySetCacheId&&=t.&&UserSecuritySetCacheId&&) as &&Child&&
from &&ContractorPersonPermTmp&& c
where  c.&&InheritedFromNumber&& > 0 
and
c.&&Contractor&& in (select ca.&&Id&& from &&Contractor&& ca  where ca.&&InheritPermissions&&=1)        and
exists (select 1 from TemplateContractorPermission t where
          &&AddPermission&& = 1 and 
          &&DelPermission&& !=1 and 
          c.&&PermissionId&&=t.&&PermissionId&& and 
          case c.&&PermissionRole&& 
		          when v_PermissionRoleAuthor then  (v_adminUser|v_usermask)
		          when v_PermissionRoleTypeResponsible then  (v_adminUser|v_usermask)
		      ELSE c.&&UserSecuritySetCacheId&&
		      end=t.&&UserSecuritySetCacheId&& and 
          c.&&PermissionRole&&=t.&&PermissionRole&&);


update &&ContractorPersonPermTmp&& c set &&InheritedFromNumber&&=c.&&InheritedFromNumber&&+t.&&Child&&
from (select &&PermissionId&&,&&UserSecuritySetCacheId&&,max(&&Child&&) as &&Child&& from &&ContractorPersonPermissionUpd&&  group by &&PermissionId&&,&&UserSecuritySetCacheId&& ) t
where t.&&PermissionId&&=c.&&PermissionId&& and t.&&UserSecuritySetCacheId&&=c.&&UserSecuritySetCacheId&&  ;



  insert into &&ContractorPersonPermissionUpd&&
  (&&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Contractor&&,&&UserSecuritySetCacheId&&,&&OrganizationItemPosition&&,&&Ins&&,&&Child&&)
  select  t.&&PermissionId&& ,t.&&User&&,t.&&Group&&,t.&&PermissionRole&&,t.&&OrganizationItemEmployee&&,c.&&Id&&,t.&&UserSecuritySetCacheId&& ,t.&&OrganizationItemPosition&&,1,count(1) as &&Child&&
  from &&Contractor&& c
  left join M_Contractor_Categories cc on c.&&Id&&=&&ContractorId&&
  left join &&TemplateContractorPermission&& t on &&AddPermission&& = 1 and &&DelPermission&& !=1 
  left outer join &&ContractorPersonPermTmp&& cp on cp.&&Contractor&&=c.&&Id&& and cp.&&PermissionId&&=t.&&PermissionId&& 
  and case cp.&&PermissionRole&& 
		          when v_PermissionRoleAuthor then  (v_adminUser|v_usermask)
		          when v_PermissionRoleTypeResponsible then  (v_adminUser|v_usermask)
		          ELSE cp.&&UserSecuritySetCacheId&&
		          end=t.&&UserSecuritySetCacheId&&  
      and cp.&&InheritedFromNumber&& > 0
  left join &&Category&& ca on ca.&&ContainerContractorPermissio&&=t.&&ContainerContractor&&
  where
  ( cc.&&CategoryId&& = ca.&&Id&& or (cc.&&CategoryId&& is null and t.&&ContainerContractor&&=v_defaultTemplCategory ) ) /* соединили категории из контейнера и из контрагента */
  and c.&&InheritPermissions&&=1
  and cp.&&Contractor&& is null
  group by t.&&PermissionId&&,t.&&User&&,t.&&Group&&,t.&&PermissionRole&&,t.&&OrganizationItemEmployee&&,c.&&Id&&,t.&&UserSecuritySetCacheId&& ,t.&&OrganizationItemPosition&&;


/*Добавить пермишены реальных пользователей для исполнителей*/
insert into &&ContractorPersonPermissionUpd&& (&&PermissionId&&,&&User&&
      ,&&Group&&
      ,&&OrganizationItemPosition&&
      ,&&UserSecuritySetCacheId&&
