delete from &&LeadPersonPermissionTmp&&;
delete from &&RelationshipPersPermTmp&&;



  delete  from &&TemplateContractorPermission&&  where &&DelPermission&& =1;
  update &&TemplateContractorPermission&& set &&AddPermission&&=0 where &&AddPermission&& =1;
  delete  from &&TemplateLeadPermission&&  where &&DelPermission&& =1;
  update &&TemplateLeadPermission&& set &&AddPermission&&=0 where &&AddPermission&& =1;

end


$$
language plpgsql;


 create or replace function CheckPermWhenAddLeadCategories (&&CategoryId&& bigint, &&LeadId&& bigint)
returns void

as
$$

declare 
v_CRMContractorCreateElementPermissionId uuid;
