v_ViewContractorPermissionId = '9219C9AB-7E68-47B1-8939-FF6FC4439DA0';
v_EditContractorPermissionId = '8C932B94-2F9C-488E-A36F-949A11C9741E';
v_FullContractorPermissionId = 'E612615C-D5E2-4c4b-9DF0-B4D9EEB983A5';


v_CRMContactCreateElementPermissionId = 'BCE45C2C-CAE1-41df-8A0A-C54E0409E8B5';
v_CRMContactIssuancePermissionId = '05D9000F-0600-49a6-8AE8-DA1DA72BFCF1';
v_ViewContactPermissionId = '3626682F-B657-419E-9A8E-392C14ABE455';
v_EditContactPermissionId = 'ABC752AD-3623-4F14-A47F-121999890D2C';
v_CRMContactFullAccessPermissionId = '76B481D5-2E07-4417-9098-A57DE879FA56';



v_CRMSaleIssuancePermissionId = 'F2141650-BB6D-4e3a-BB62-C0F071CF8EEA';
v_ViewSalePermissionId = 'AAE16346-B0E6-4949-ACAB-0914C573DE55';
v_EditSalePermissionId = 'AF2CEF4B-F639-49B4-BD88-363F20BD5A74';
v_CRMSaleCreateElementPermissionId = '7DB77821-D6D3-4dd2-AD1B-798330506ADC';
v_FullSalePermissionId = 'DB60BB49-0DE1-46ee-8CE8-DCD59DB93351';


v_CRMInpaymentCreateElementPermissionId = 'D130BB5F-6A26-4e37-B62C-F3B443E3BF53';
v_ViewInpaymentPermissionId  = '837FF0F3-03A7-4A17-86EA-A72B3AB4886B';
v_EditInpaymentPermissionId  = 'E23802D7-F3B5-431E-A72E-7133C3C9343F';
v_CRMInpaymentIssuanceElementPermissionId  = 'ACF5606C-B566-426b-BAEC-E74061095BEB';
v_CRMInpaymentFullAccessPermissionId  = 'A27A46F9-BCD8-4e82-AE49-E58675DE52D7';

v_ViewLeadPermissionId = 'C660E4B4-03BF-4315-9600-5086E47653B4';
v_EditLeadPermissionId = 'AE298CD3-A16A-4B55-ACFC-545E4A0EBD48';
v_CRMLeadCreateElementPermissionId = '643FE44B-8192-4615-B853-106CD6F09EDE';
v_CRMLeadFullAccessPermissionId = '90BE803C-7857-4F2D-A8B4-129264504101';
v_CRMLeadIssuanceElementPermissionId = 'E70A9AD1-80B2-4435-80E9-EF8E14B974CE';

v_CRMRelationshipCreateElementPermissionId = 'BA5E9414-B347-4eaa-A019-14D4FA02F5E2';
v_ViewRelationshipPermissionId = '186D4CC4-6924-4848-93AC-6D8DE389CB08';
v_EditRelationshipPermissionId  = '0B980531-D097-4EC1-8616-56E6AB15770E';
v_CRMRelationshipIssuanceElementPermissionId  = '679876A7-8882-43d4-8FC2-3E7C9DB58ADB';
v_CRMRelationshipFullAccessPermissionId = '38A0AC5D-8D9C-4BB5-BDBA-A0E6CFD43C30';


delete from  &&RelationshipPersonPermUpd&&;
delete from &&TemplateLeadPermUpd&&;
delete from &&LeadPersonPermissionUpd&&;

insert into &&TemplateLeadPermUpd&& ( &&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&UserSecuritySetCacheId&&,&&OrganizationItemPosition&&,&&Lead&&)
          select  &&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&UserSecuritySetCacheId&&,&&OrganizationItemPosition&&,&&ContainerLead&&

from &&TemplateLeadPermission&& t
join &&Category&& c on c.&&ContainerLeadPermission&&=t.&&ContainerLead&&
where c.&&Id&&=$1 and  &&AddPermission&& !=1 and &&DelPermission&&!=1 ;

insert into &&LeadPersonPermissionUpd&& (&&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Lead&&,&&UserSecuritySetCacheId&&,&&OrganizationItemPosition&&, &&Ins&& ,&&Child&&)
select  t.&&PermissionId&&,t.&&User&&,t.&&Group&&,t.&&PermissionRole&&,t.&&OrganizationItemEmployee&&,ca.&&Id&& &&Lead&&,t.&&UserSecuritySetCacheId&&,t.&&OrganizationItemPosition&&,0 &&Ins&&
,count(1) as &&Child&&
from &&LeadPersonPermission&& c
left join &&TemplateLeadPermUpd&& t on c.&&PermissionId&&=t.&&PermissionId&& and c.&&UserSecuritySetCacheId&&=t.&&UserSecuritySetCacheId&&
left join &&Lead&& ca on c.&&Lead&&=ca.&&Id&& and ca.&&InheritPermissions&&=1
where  c.&&InheritedFromNumber&& > 0
and t.&&PermissionId&& is not null
and c.&&Lead&&=$2
group by t.&&PermissionId&&,t.&&User&&,t.&&Group&&,t.&&PermissionRole&&,t.&&OrganizationItemEmployee&&,ca.&&Id&&,t.&&UserSecuritySetCacheId&&,t.&&OrganizationItemPosition&&;


update &&LeadPersonPermission&& c set &&InheritedFromNumber&&=c.&&InheritedFromNumber&&+t.&&Child&&
from (select &&UserSecuritySetCacheId&&, &&PermissionId&&, max(&&Child&&) as  &&Child&& from &&LeadPersonPermissionUpd&& group by &&UserSecuritySetCacheId&&, &&PermissionId&& ) t
where t.&&PermissionId&&=c.&&PermissionId&& and t.&&UserSecuritySetCacheId&&=c.&&UserSecuritySetCacheId&&
and c.&&Lead&&= $2 ;

insert into &&LeadPersonPermissionUpd&&
(&&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Lead&&,&&UserSecuritySetCacheId&&,&&OrganizationItemPosition&&,&&Ins&&,&&Child&&)
select  t.&&PermissionId&& ,t.&&User&&,t.&&Group&&,t.&&PermissionRole&&,t.&&OrganizationItemEmployee&&,c.&&Id&&,t.&&UserSecuritySetCacheId&& ,t.&&OrganizationItemPosition&&,1,count(1) as &&Child&&
from &&Lead&& c
  join &&TemplateLeadPermUpd&& t on 1=1
left outer join &&LeadPersonPermission&& cp on cp.&&Lead&&=c.&&Id&& and cp.&&PermissionId&&=t.&&PermissionId&& and cp.&&UserSecuritySetCacheId&&=t.&&UserSecuritySetCacheId&& and cp.&&InheritedFromNumber&& > 0
left join &&Category&& ca on  ca.&&ContainerLeadPermission&&=t.&&Lead&& 
where
  c.&&InheritPermissions&&>=1
and cp.&&Lead&& is null
and c.&&Id&&=$2
group by t.&&PermissionId&& ,t.&&User&&,t.&&Group&&,t.&&PermissionRole&&,t.&&OrganizationItemEmployee&&,c.&&Id&&,t.&&UserSecuritySetCacheId&& ,t.&&OrganizationItemPosition&&;


   /*Перезаписать реальных пользователей в ответственных */
      update &&LeadPersonPermissionUpd&& 
        set
        &&User&& = (select Responsible from &&Lead&& con where con.&&Id&&=&&Lead&&),
        &&UserSecuritySetCacheId&& = (select (Responsible | v_UserMask) from &&Lead&& con where con.&&Id&&=&&Lead&&)
      where PermissionRole=v_PermissionRoleTypeResp ; 

insert into &&LeadPersonPermission&& (&&Id&&,&&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Lead&&,&&UserSecuritySetCacheId&&,&&Uid&&,&&InheritedFromNumber&&,&&OrganizationItemPosition&&)
select  nextval('G_LeadPERSONPERMISSION') as &&Id&&,  t.&&PermissionId&& ,t.&&User&&,t.&&Group&&,t.&&PermissionRole&&,t.&&OrganizationItemEmployee&&,&&Lead&&,t.&&UserSecuritySetCacheId&&,uuid_generate_v4()  as &&Uid&&,&&Child&& as &&InheritedFromNumber&&,t.&&OrganizationItemPosition&&
from  &&LeadPersonPermissionUpd&& t where &&Ins&&=1;


insert into &&RelationshipPersonPermUpd&&( &&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Relationship&&,&&UserSecuritySetCacheId&&,&&OrganizationItemPosition&&,&&Ins&&)
select  c.&&PermissionId&&,t.&&User&&,t.&&Group&&,t.&&PermissionRole&&,t.&&OrganizationItemEmployee&&,ca.&&Id&& &&Relationship&&,t.&&UserSecuritySetCacheId&&,t.&&OrganizationItemPosition&&,0 &&Ins&&
from &&RelationshipPersonPermission&& c
left join &&Relationship&& r on r.&&Id&&=c.&&Relationship&& and r.&&Lead&& is not null
left join &&LeadPersonPermissionUpd&& t on

case
when t.&&PermissionId&&= v_CRMLeadCreateElementPermissionId then v_CRMRelationshipCreateElementPermissionId
when t.&&PermissionId&&= v_CRMLeadIssuanceElementPermissionId then v_CRMRelationshipIssuanceElementPermissionId
when t.&&PermissionId&&= v_ViewLeadPermissionId then v_ViewRelationshipPermissionId
when t.&&PermissionId&&= v_EditLeadPermissionId then v_EditRelationshipPermissionId
when t.&&PermissionId&&= v_CRMLeadFullAccessPermissionId then v_CRMRelationshipFullAccessPermissionId
else t.&&PermissionId&&
end =
c.&&PermissionId&& and c.&&UserSecuritySetCacheId&&=t.&&UserSecuritySetCacheId&&
left join &&Relationship&& ca on c.&&Relationship&&=ca.&&Id&& and ca.&&InheritPermissions&&=1
where  c.&&InheritedFromNumber&& > 0
and t.&&UserSecuritySetCacheId&& is not null ;

update &&RelationshipPersonPermission&& c set &&InheritedFromNumber&&=c.&&InheritedFromNumber&&+1
where exists (select &&Id&& from &&RelationshipPersonPermUpd&& t where t.&&PermissionId&&=c.&&PermissionId&& and t.&&UserSecuritySetCacheId&&=c.&&UserSecuritySetCacheId&& )   ;



insert into &&RelationshipPersonPermUpd&&  (&&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Relationship&&,&&UserSecuritySetCacheId&&,&&OrganizationItemPosition&&,&&Ins&&)

select
case
when t.&&PermissionId&&= v_CRMLeadCreateElementPermissionId then v_CRMRelationshipCreateElementPermissionId
when t.&&PermissionId&&= v_CRMLeadIssuanceElementPermissionId then v_CRMRelationshipIssuanceElementPermissionId
when t.&&PermissionId&&= v_ViewLeadPermissionId then v_ViewRelationshipPermissionId
when t.&&PermissionId&&= v_EditLeadPermissionId then v_EditRelationshipPermissionId
when t.&&PermissionId&&= v_CRMLeadFullAccessPermissionId then v_CRMRelationshipFullAccessPermissionId
else t.&&PermissionId&&
end 

,t.&&User&&,t.&&Group&&,t.&&PermissionRole&&,t.&&OrganizationItemEmployee&&,c.&&Id&& &&Relationship&&,t.&&UserSecuritySetCacheId&&,t.&&OrganizationItemPosition&&,1 &&Ins&&

from &&Relationship&& c
left join &&LeadPersonPermissionUpd&& t on t.&&Lead&&=c.&&Lead&& 
left outer join &&RelationshipPersonPermission&& cp on cp.&&Relationship&&=c.&&Id&& and cp.&&InheritedFromNumber&& > 0 and
case
when t.&&PermissionId&&= v_CRMLeadCreateElementPermissionId then v_CRMRelationshipCreateElementPermissionId
when t.&&PermissionId&&= v_CRMLeadIssuanceElementPermissionId then v_CRMRelationshipIssuanceElementPermissionId
when t.&&PermissionId&&= v_ViewLeadPermissionId then v_ViewRelationshipPermissionId
when t.&&PermissionId&&= v_EditLeadPermissionId then v_EditRelationshipPermissionId
when t.&&PermissionId&&= v_CRMLeadFullAccessPermissionId then v_CRMRelationshipFullAccessPermissionId
else t.&&PermissionId&&
end =

cp.&&PermissionId&& and cp.&&UserSecuritySetCacheId&&=t.&&UserSecuritySetCacheId&&
where  t.&&Lead&& is not null 
and c.&&InheritPermissions&&=1
and c.&&Lead&& is not null
and cp.&&Relationship&& is null;



insert into &&RelationshipPersonPermission&& (&&Id&&,&&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Relationship&&,&&UserSecuritySetCacheId&&,&&Uid&&,&&InheritedFromNumber&&,&&OrganizationItemPosition&&)
select  nextval('G_RelationshipPERSONPERMISSION')  &&Id&&,t.&&PermissionId&& ,t.&&User&&,t.&&Group&&,t.&&PermissionRole&&,t.&&OrganizationItemEmployee&&,&&Relationship&&,t.&&UserSecuritySetCacheId&&,uuid_generate_v4() ,1 ,t.&&OrganizationItemPosition&&
from  &&RelationshipPersonPermUpd&& t where &&Ins&&=1;

delete from  &&RelationshipPersonPermUpd&&;
delete from &&LeadPersonPermissionUpd&&;

end

$$
language plpgsql;

CREATE OR REPLACE FUNCTION CheckPermWhenAddCategories(CategoryId bigint, ContractorId bigint) RETURNS void
AS $$
DECLARE
v_AdminUid uuid; v_AdminUser bigint; v_UserMask bigint;
v_CRMContractorCreateElementPermissionId uuid; v_CRMContractorIssuancePermissionId uuid; v_ViewContractorPermissionId uuid; v_EditContractorPermissionId uuid; v_FullContractorPermissionId uuid;
v_CRMContactCreateElementPermissionId uuid; v_CRMContactIssuancePermissionId uuid; v_ViewContactPermissionId uuid; v_EditContactPermissionId uuid; v_CRMContactFullAccessPermissionId uuid;
v_CRMSaleCreateElementPermissionId uuid; v_CRMSaleIssuancePermissionId uuid; v_ViewSalePermissionId uuid; v_EditSalePermissionId uuid; v_FullSalePermissionId uuid;
v_CRMRelationshipCreateElementPermissionId uuid; v_CRMRelationshipIssuanceElementPermissionId uuid; v_CRMRelationshipFullAccessPermissionId uuid; v_ViewRelationshipPermissionId uuid; v_EditRelationshipPermissionId uuid;
v_PermissionRoleTypeParticipantWork uuid; v_PermissionRoleAuthor uuid; v_PermissionRoleTypeInforms uuid; v_PermissionRoleTypeResponsible uuid;
BEGIN
v_AdminUid = 'F0E949BF-4DA4-4C02-B04C-CA61964B4FE8'; v_UserMask = 72057594037927936; -- побитовый сдвиг влево 1 на 56 разрядов (2 ^ 56) 1055
v_CRMContractorCreateElementPermissionId = '44ED88D4-A466-4fed-B194-B8288560CB48'; v_CRMContractorIssuancePermissionId = '1CD25727-7CE6-443c-84BD-7975822C79E6'; v_ViewContractorPermissionId = '9219C9AB-7E68-47B1-8939-FF6FC4439DA0'; v_EditContractorPermissionId = '8C932B94-2F9C-488E-A36F-949A11C9741E'; v_FullContractorPermissionId = 'E612615C-D5E2-4c4b-9DF0-B4D9EEB983A5';
v_CRMContactCreateElementPermissionId = 'BCE45C2C-CAE1-41df-8A0A-C54E0409E8B5'; v_CRMContactIssuancePermissionId = '05D9000F-0600-49a6-8AE8-DA1DA72BFCF1'; v_ViewContactPermissionId = '3626682F-B657-419E-9A8E-392C14ABE455'; v_EditContactPermissionId = 'ABC752AD-3623-4F14-A47F-121999890D2C'; v_CRMContactFullAccessPermissionId = '76B481D5-2E07-4417-9098-A57DE879FA56';
v_CRMSaleIssuancePermissionId = 'F2141650-BB6D-4e3a-BB62-C0F071CF8EEA'; v_ViewSalePermissionId = 'AAE16346-B0E6-4949-ACAB-0914C573DE55'; v_EditSalePermissionId = 'AF2CEF4B-F639-49B4-BD88-363F20BD5A74'; v_CRMSaleCreateElementPermissionId = '7DB77821-D6D3-4dd2-AD1B-798330506ADC'; v_FullSalePermissionId = 'DB60BB49-0DE1-46ee-8CE8-DCD59DB93351';
v_CRMRelationshipCreateElementPermissionId = 'BA5E9414-B347-4eaa-A019-14D4FA02F5E2'; v_ViewRelationshipPermissionId = '186D4CC4-6924-4848-93AC-6D8DE389CB08'; v_EditRelationshipPermissionId = '0B980531-D097-4EC1-8616-56E6AB15770E'; v_CRMRelationshipIssuanceElementPermissionId = '679876A7-8882-43d4-8FC2-3E7C9DB58ADB'; v_CRMRelationshipFullAccessPermissionId = '38A0AC5D-8D9C-4BB5-BDBA-A0E6CFD43C30';
v_PermissionRoleTypeParticipantWork = '9A945D2E-BCFA-4AF4-8653-9A67A5ED6386'; v_PermissionRoleAuthor = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92'; v_PermissionRoleTypeInforms = '21888C0C-8BCA-4B26-AF13-4C497EECCED6'; v_PermissionRoleTypeResponsible = 'CE4D6154-E36E-406b-8BE9-25266C5BDD15';
DELETE FROM &&ContractorPersonPermissionUpd&&; DELETE FROM &&ContactPersonPermissionUpd&&; DELETE FROM &&SalePersonPermissionUpd&&; DELETE FROM &&RelationshipPersonPermUpd&&;
SELECT u.&&Id&& FROM &&User&& u WHERE u.&&Uid&& = v_AdminUid INTO v_AdminUser;
/***************************************************************************************************** * * КОНТРАГЕНТЫ * *****************************************************************************************************/ DROP TABLE IF EXISTS &&TemplateContractorPermissionAdd&&; CREATE TEMP TABLE &&TemplateContractorPermissionAdd&& ON COMMIT DROP AS SELECT t.* FROM &&TemplateContractorPermission&& t JOIN &&Category&& c ON c.ContainerContractorPermissio = t.ContainerContractor WHERE c.&&Id&& = $1 AND AddPermission != 1 AND DelPermission != 1;
-- Добавить привилегии в контрагента INSERT INTO &&ContractorPersonPermissionUpd&& (&&PermissionId&&, &&User&&, &&Group&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Contractor&&, &&UserSecuritySetCacheId&&, &&OrganizationItemPosition&&, &&Ins&&, &&Child&& ) SELECT t.&&PermissionId&&, t.&&User&&, t.&&Group&&, t.&&PermissionRole&&, t.&&OrganizationItemEmployee&&, ca.&&Id&& AS &&Contractor&&, t.&&UserSecuritySetCacheId&&, t.&&OrganizationItemPosition&&, 0 AS &&Ins&&, COUNT(1) AS &&Child&& FROM &&ContractorPersonPermission&& c LEFT JOIN &&TemplateContractorPermissionAdd&& t ON c.&&PermissionId&& = t.&&PermissionId&& AND CASE c.&&PermissionRole&& WHEN v_PermissionRoleAuthor THEN(v_AdminUser | v_UserMask) WHEN v_PermissionRoleTypeResponsible THEN(v_AdminUser | v_UserMask) ELSE c.&&UserSecuritySetCacheId&& END = t.&&UserSecuritySetCacheId&& AND c.&&PermissionRole&& = t.&&PermissionRole&& LEFT JOIN &&Contractor&& ca ON c.&&Contractor&& = ca.&&Id&& AND ca.&&InheritPermissions&& = 1 WHERE c.&&InheritedFromNumber&& > 0 AND t.&&Id&& IS NOT NULL AND c.&&Contractor&& = $2 GROUP BY t.&&PermissionId&&, t.&&User&&, t.&&Group&&, t.&&PermissionRole&&, t.&&OrganizationItemEmployee&&, ca.&&Id&&, t.&&UserSecuritySetCacheId&&, t.&&OrganizationItemPosition&&;
-- Добавить пермишены реальных пользователей для исполнителей INSERT INTO &&ContractorPersonPermissionUpd&& (&&PermissionId&&, &&User&&, &&Group&&, &&OrganizationItemPosition&&, &&UserSecuritySetCacheId&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Contractor&&, &&Ins&&, &&Child&& ) SELECT c.&&PermissionId&&, m.&&Child&& AS &&User&&, c.&&Group&&, c.&&OrganizationItemPosition&&, (m.&&Child&& | v_UserMask) AS &&UserSecuritySetCacheId&&, c.&&PermissionRole&&, c.&&OrganizationItemEmployee&&, c.&&Contractor&&, 0 AS &&Ins&&, c.&&Child&& FROM M_Contractor_ParticipantWork m LEFT JOIN &&ContractorPersonPermissionUpd&& c ON m.&&Parent&& = c.&&Contractor&& WHERE c.&&PermissionRole&& = v_PermissionRoleTypeParticipantWork AND c.&&User&& = v_AdminUser AND &&Ins&& = 0 GROUP BY c.&&PermissionId&&, m.&&Child&&, c.&&Group&&, c.&&OrganizationItemPosition&&, c.&&PermissionRole&&, c.&&OrganizationItemEmployee&&, c.&&Contractor&&, c.&&Child&&;
INSERT INTO &&ContractorPersonPermissionUpd&& (&&PermissionId&&, &&User&&, &&Group&&, &&OrganizationItemPosition&&, &&UserSecuritySetCacheId&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Contractor&&, &&Ins&&, &&Child&& ) SELECT c.&&PermissionId&&, m.&&Child&& AS &&User&&, c.&&Group&&, c.&&OrganizationItemPosition&&, (m.&&Child&& | v_UserMask) AS &&UserSecuritySetCacheId&&, c.&&PermissionRole&&, c.&&OrganizationItemEmployee&&, c.&&Contractor&&, 0 AS &&Ins&&, c.&&Child&& FROM M_Contractor_Informs m LEFT JOIN &&ContractorPersonPermissionUpd&& c ON m.&&Parent&& = c.&&Contractor&& WHERE c.&&PermissionRole&& = v_PermissionRoleTypeInforms AND &&User&& = v_AdminUser AND &&Ins&& = 0 GROUP BY c.&&PermissionId&&, m.&&Child&&, c.&&Group&&, c.&&OrganizationItemPosition&&, c.&&PermissionRole&&, c.&&OrganizationItemEmployee&&, c.&&Contractor&&, c.&&Child&&;
UPDATE &&ContractorPersonPermission&& c SET &&InheritedFromNumber&& = &&InheritedFromNumber&& + t.&&Child&& FROM (SELECT &&UserSecuritySetCacheId&&, &&PermissionId&&, MAX(t.&&Child&&) AS &&Child&& FROM &&ContractorPersonPermissionUpd&& t GROUP BY &&UserSecuritySetCacheId&&, &&PermissionId&&) t WHERE t.&&PermissionId&& = c.&&PermissionId&& AND t.&&UserSecuritySetCacheId&& = c.&&UserSecuritySetCacheId&& AND c.&&Contractor&& = $2;
-- Добавить недостающие привилегии в контрагента INSERT INTO &&ContractorPersonPermissionUpd&& (&&PermissionId&&, &&User&&, &&Group&&, &&OrganizationItemPosition&&, &&UserSecuritySetCacheId&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Contractor&&, &&Ins&&, &&Child&& ) SELECT t.&&PermissionId&&, t.&&User&&, t.&&Group&&, t.&&OrganizationItemPosition&&, t.&&UserSecuritySetCacheId&&, t.&&PermissionRole&&, t.&&OrganizationItemEmployee&&, c.&&Id&&, 1 AS &&Ins&&, COUNT(1) AS &&Child&& FROM &&Contractor&& c JOIN &&TemplateContractorPermissionAdd&& t ON 1 = 1 -- взяли пермишены которые надо обновить из контейнера LEFT JOIN &&ContractorPersonPermission&& cp ON cp.&&Contractor&& = c.&&Id&& AND cp.&&PermissionId&& = t.&&PermissionId&& AND CASE cp.&&PermissionRole&& WHEN v_PermissionRoleAuthor THEN(v_AdminUser | v_UserMask) WHEN v_PermissionRoleTypeResponsible THEN(v_AdminUser | v_UserMask) ELSE cp.&&UserSecuritySetCacheId&& END = t.&&UserSecuritySetCacheId&& AND cp.&&PermissionRole&& = t.&&PermissionRole&& AND cp.&&InheritedFromNumber&& > 0 LEFT JOIN &&Category&& ca ON ca.ContainerContractorPermissio = t.ContainerContractor -- вытащили категорию в которую входит пермишен из контейнера WHERE -- соединили категории из контейнера и из контрагента c.&&InheritPermissions&& >= 1 AND cp.&&Contractor&& IS NULL AND c.&&Id&& = $2 GROUP BY t.&&PermissionId&&, t.&&User&&, t.&&Group&&, t.&&PermissionRole&&, t.&&OrganizationItemEmployee&&, c.&&Id&&, t.&&UserSecuritySetCacheId&&, t.&&OrganizationItemPosition&&;
-- Добавить пермишены реальных пользователей для исполнителей INSERT INTO &&ContractorPersonPermissionUpd&& (&&PermissionId&&, &&User&&, &&Group&&, &&OrganizationItemPosition&&, &&UserSecuritySetCacheId&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Contractor&&, &&Ins&&, &&Child&& ) SELECT c.&&PermissionId&&, m.&&Child&& AS &&User&&, c.&&Group&&, c.&&OrganizationItemPosition&&, (m.&&Child&& | v_UserMask) AS &&UserSecuritySetCacheId&&, c.&&PermissionRole&&, c.&&OrganizationItemEmployee&&, c.&&Contractor&&, 1 AS &&Ins&&, c.&&Child&& FROM M_Contractor_ParticipantWork m LEFT JOIN &&ContractorPersonPermissionUpd&& c ON m.&&Parent&& = c.&&Contractor&& WHERE &&PermissionRole&& = v_PermissionRoleTypeParticipantWork AND &&User&& = v_AdminUser AND &&Ins&& = 1 GROUP BY c.&&PermissionId&&, c.&&User&&, c.&&Group&&, c.&&PermissionRole&&, c.&&OrganizationItemEmployee&&, c.&&Id&&, c.&&UserSecuritySetCacheId&&, c.&&OrganizationItemPosition&&, m.&&Child&&, c.&&Contractor&&, c.&&Child&&;
INSERT INTO &&ContractorPersonPermissionUpd&& (&&PermissionId&&, &&User&&, &&Group&&, &&OrganizationItemPosition&&, &&UserSecuritySetCacheId&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Contractor&&, &&Ins&&, &&Child&& ) SELECT c.&&PermissionId&&, m.&&Child&& AS &&User&&, c.&&Group&&, c.&&OrganizationItemPosition&&, (m.&&Child&& | v_UserMask) AS &&UserSecuritySetCacheId&&, c.&&PermissionRole&&, c.&&OrganizationItemEmployee&&, c.&&Contractor&&, 1 AS &&Ins&&, c.&&Child&& FROM M_Contractor_Informs m LEFT JOIN &&ContractorPersonPermissionUpd&& c ON m.&&Parent&& = c.&&Contractor&& WHERE &&PermissionRole&& = v_PermissionRoleTypeInforms AND &&User&& = v_AdminUser AND &&Ins&& = 1 GROUP BY c.&&PermissionId&&, c.&&User&&, c.&&Group&&, c.&&PermissionRole&&, c.&&OrganizationItemEmployee&&, c.&&Id&&, c.&&UserSecuritySetCacheId&&, c.&&OrganizationItemPosition&&, m.&&Child&&, c.&&Contractor&&, c.&&Child&&;
-- Перезаписать реальных пользователей в ответственных UPDATE &&ContractorPersonPermissionUpd&& SET &&User&& = (SELECT &&Responsible&& FROM &&Contractor&& con WHERE con.&&Id&& = &&Contractor&&), &&UserSecuritySetCacheId&& = (SELECT (&&Responsible&& | v_UserMask) FROM &&Contractor&& con WHERE con.&&Id&& = &&Contractor&&) WHERE &&PermissionRole&& = v_PermissionRoleTypeResponsible;
-- Перезаписать реальных пользователей в ответственных UPDATE &&ContractorPersonPermissionUpd&& SET &&User&& = (SELECT &&CreationAuthor&& FROM &&Contractor&& con WHERE con.&&Id&& = &&Contractor&&), &&UserSecuritySetCacheId&& = (SELECT (&&CreationAuthor&& | v_UserMask) FROM &&Contractor&& con WHERE con.&&Id&& = &&Contractor&&) WHERE &&PermissionRole&& = v_PermissionRoleAuthor;
INSERT INTO &&ContractorPersonPermission&& (&&Id&&, &&PermissionId&&, &&User&&, &&Group&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Contractor&&, &&UserSecuritySetCacheId&&, &&Uid&&, &&InheritedFromNumber&&, &&OrganizationItemPosition&& ) SELECT NEXTVAL('G_contractorPERSONPERMISSION') AS &&Id&&, t.&&PermissionId&&, t.&&User&&, t.&&Group&&, t.&&PermissionRole&&, t.&&OrganizationItemEmployee&&, t.&&Contractor&&, t.&&UserSecuritySetCacheId&&, UUID_GENERATE_V4() AS &&Uid&&, t.&&Child&& AS &&InheritedFromNumber&&, t.&&OrganizationItemPosition&& FROM &&ContractorPersonPermissionUpd&& t WHERE &&Ins&& = 1;
