-- UPDATE &&ContactPersonPermission&& c -- SET &&InheritedFromNumber&& = &&InheritedFromNumber&& + 1 -- WHERE EXISTS(SELECT 1 FROM &&ContactPersonPermissionUpd&& t WHERE t.&&Id&& = c.&&Id&& -- AND t.&&Contact&& = c.&&Contact&&);
-- Добавить недостающие привилегии к контактам INSERT INTO &&ContactPersonPermissionUpd&& (&&PermissionId&&, &&User&&, &&Group&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Contact&&, &&UserSecuritySetCacheId&&, &&OrganizationItemPosition&&, &&Ins&& ) SELECT CASE WHEN t.&&PermissionId&& = v_CRMContractorCreateElementPermissionId THEN v_CRMContactCreateElementPermissionId WHEN t.&&PermissionId&& = v_CRMContractorIssuancePermissionId THEN v_CRMContactIssuancePermissionId WHEN t.&&PermissionId&& = v_ViewContractorPermissionId THEN v_ViewContactPermissionId WHEN t.&&PermissionId&& = v_EditContractorPermissionId THEN v_EditContactPermissionId WHEN t.&&PermissionId&& = v_FullContractorPermissionId THEN v_CRMContactFullAccessPermissionId ELSE t.&&PermissionId&& END, t.&&User&&, t.&&Group&&, t.&&PermissionRole&&, t.&&OrganizationItemEmployee&&, c.&&Id&& AS &&Contact&&, t.&&UserSecuritySetCacheId&&, t.&&OrganizationItemPosition&&, 1 AS &&Ins&& FROM &&Contact&& c LEFT JOIN &&ContractorPersonPermissionUpd&& t ON t.&&Contractor&& = c.&&Contractor&& LEFT OUTER JOIN &&ContactPersonPermission&& cp ON cp.&&Contact&& = c.&&Id&& AND cp.&&InheritedFromNumber&& > 0 AND CASE WHEN t.&&PermissionId&& = v_CRMContractorCreateElementPermissionId THEN v_CRMContactCreateElementPermissionId WHEN t.&&PermissionId&& = v_CRMContractorIssuancePermissionId THEN v_CRMContactIssuancePermissionId WHEN t.&&PermissionId&& = v_ViewContractorPermissionId THEN v_ViewContactPermissionId WHEN t.&&PermissionId&& = v_EditContractorPermissionId THEN v_EditContactPermissionId WHEN t.&&PermissionId&& = v_FullContractorPermissionId THEN v_CRMContactFullAccessPermissionId ELSE t.&&PermissionId&& END = cp.&&PermissionId&& AND cp.&&UserSecuritySetCacheId&& = t.&&UserSecuritySetCacheId&& AND cp.&&PermissionRole&& = t.&&PermissionRole&& WHERE t.&&Contractor&& IS NOT NULL AND cp.&&Contact&& IS NULL AND c.&&InheritPermissions&& = 1;
-- Перезаписать реальных пользователей в ответственных UPDATE &&ContactPersonPermissionUpd&& SET &&User&& = (SELECT contr.&&Responsible&& FROM &&Contact&& con LEFT JOIN &&Contractor&& contr ON contr.&&Id&& = con.&&Contractor&& WHERE con.&&Id&& = &&Contact&&), &&UserSecuritySetCacheId&& = (SELECT (contr.&&Responsible&& | v_UserMask) FROM &&Contact&& con LEFT JOIN &&Contractor&& contr ON contr.&&Id&& = con.&&Contractor&& WHERE con.&&Id&& = &&Contact&&) WHERE &&PermissionRole&& = v_PermissionRoleTypeResponsible;
-- Перезаписать реальных пользователей в ответственных UPDATE &&ContactPersonPermissionUpd&& SET &&User&& = (SELECT &&CreationAuthor&& FROM &&Contact&& con WHERE con.&&Id&& = &&Contact&&), &&UserSecuritySetCacheId&& = (SELECT (&&CreationAuthor&& | v_UserMask) FROM &&Contact&& con WHERE con.&&Id&& = &&Contact&&) WHERE &&PermissionRole&& = v_PermissionRoleAuthor;
INSERT INTO &&ContactPersonPermission&& (&&Id&&, &&PermissionId&&, &&User&&, &&Group&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Contact&&, &&UserSecuritySetCacheId&&, &&Uid&&, &&InheritedFromNumber&&, &&OrganizationItemPosition&& ) SELECT NEXTVAL('G_CONTACTPERSONPERMISSION') AS &&Id&&, t.&&PermissionId&&, t.&&User&&, t.&&Group&&, t.&&PermissionRole&&, t.&&OrganizationItemEmployee&&, t.&&Contact&&, t.&&UserSecuritySetCacheId&&, UUID_GENERATE_V4() AS &&Uid&&, 1 AS &&InheritedFromNumber&&, t.&&OrganizationItemPosition&& FROM &&ContactPersonPermissionUpd&& t WHERE &&Ins&& = 1;
/***************************************************************************************************** * * СДЕЛКИ * *****************************************************************************************************/ INSERT INTO &&SalePersonPermissionUpd&& (&&PermissionId&&, &&User&&, &&Group&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Sale&&, &&UserSecuritySetCacheId&&, &&OrganizationItemPosition&&, &&Ins&& ) SELECT c.&&PermissionId&&, t.&&User&&, t.&&Group&&, t.&&PermissionRole&&, t.&&OrganizationItemEmployee&&, ca.&&Id&& AS &&Sale&&, t.&&UserSecuritySetCacheId&&, t.&&OrganizationItemPosition&&, 0 AS &&Ins&& FROM &&SalePersonPermission&& c LEFT JOIN &&ContractorPersonPermissionUpd&& t ON CASE WHEN t.&&PermissionId&& = v_CRMContractorCreateElementPermissionId THEN v_CRMSaleCreateElementPermissionId WHEN t.&&PermissionId&& = v_CRMContractorIssuancePermissionId THEN v_CRMSaleIssuancePermissionId WHEN t.&&PermissionId&& = v_ViewContractorPermissionId THEN v_ViewSalePermissionId WHEN t.&&PermissionId&& = v_EditContractorPermissionId THEN v_EditSalePermissionId WHEN t.&&PermissionId&& = v_FullContractorPermissionId THEN v_FullSalePermissionId ELSE t.&&PermissionId&& END = c.&&PermissionId&& AND c.&&UserSecuritySetCacheId&& = CASE c.&&PermissionRole&& WHEN v_PermissionRoleAuthor THEN (SELECT (&&Author&& | v_UserMask) FROM &&Sale&& con WHERE con.&&Id&& = c.&&Sale&&) WHEN v_PermissionRoleTypeResponsible THEN (SELECT (&&Responsible&& | v_UserMask) FROM &&Sale&& con WHERE con.&&Id&& = c.&&Sale&&) ELSE t.&&UserSecuritySetCacheId&& END AND c.&&PermissionRole&& = t.&&PermissionRole&& LEFT JOIN &&Sale&& ca ON c.&&Sale&& = ca.&&Id&& AND ca.&&InheritPermissions&& = 1 WHERE c.&&InheritedFromNumber&& > 0 AND t.&&UserSecuritySetCacheId&& IS NOT NULL;
-- UPDATE &&SalePersonPermission&& c -- SET &&InheritedFromNumber&& = &&InheritedFromNumber&& + 1 -- WHERE EXISTS(SELECT 1 -- FROM &&SalePersonPermissionUpd&& t -- WHERE t.&&Id&& = c.&&Id&& AND t.&&Sale&& = c.&&Sale&&);
-- Добавить недостающие привилегии к сделкам INSERT INTO &&SalePersonPermissionUpd&& (&&PermissionId&&, &&User&&, &&Group&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Sale&&, &&UserSecuritySetCacheId&&, &&OrganizationItemPosition&&, &&Ins&& )
SELECT CASE WHEN t.&&PermissionId&& = v_CRMContractorCreateElementPermissionId THEN v_CRMSaleCreateElementPermissionId WHEN t.&&PermissionId&& = v_CRMContractorIssuancePermissionId THEN v_CRMSaleIssuancePermissionId WHEN t.&&PermissionId&& = v_ViewContractorPermissionId THEN v_ViewSalePermissionId WHEN t.&&PermissionId&& = v_EditContractorPermissionId THEN v_EditSalePermissionId WHEN t.&&PermissionId&& = v_FullContractorPermissionId THEN v_FullSalePermissionId ELSE t.&&PermissionId&& END, t.&&User&&, t.&&Group&&, t.&&PermissionRole&&, t.&&OrganizationItemEmployee&&, c.&&Id&& AS &&Sale&&, t.&&UserSecuritySetCacheId&&, t.&&OrganizationItemPosition&&, 1 AS &&Ins&& FROM &&Sale&& c LEFT JOIN &&ContractorPersonPermissionUpd&& t ON t.&&Contractor&& = c.&&Contractor&& LEFT OUTER JOIN &&SalePersonPermission&& cp ON cp.&&Sale&& = c.&&Id&& AND cp.&&InheritedFromNumber&& > 0 AND CASE WHEN t.&&PermissionId&& = v_CRMContractorCreateElementPermissionId THEN v_CRMSaleCreateElementPermissionId WHEN t.&&PermissionId&& = v_CRMContractorIssuancePermissionId THEN v_CRMSaleIssuancePermissionId WHEN t.&&PermissionId&& = v_ViewContractorPermissionId THEN v_ViewSalePermissionId WHEN t.&&PermissionId&& = v_EditContractorPermissionId THEN v_EditSalePermissionId WHEN t.&&PermissionId&& = v_FullContractorPermissionId THEN v_FullSalePermissionId ELSE t.&&PermissionId&& END = cp.&&PermissionId&& AND cp.&&UserSecuritySetCacheId&& = t.&&UserSecuritySetCacheId&& AND cp.&&PermissionRole&& = t.&&PermissionRole&& WHERE t.&&Contractor&& IS NOT NULL AND c.&&InheritPermissions&& = 1 AND cp.&&Sale&& IS NULL;
-- Перезаписать реальных пользователей в ответственных UPDATE &&SalePersonPermissionUpd&& SET &&User&& = (SELECT &&Responsible&& FROM &&Sale&& con WHERE con.&&Id&& = &&Sale&&), &&UserSecuritySetCacheId&& = (SELECT (&&Responsible&& | v_UserMask) FROM &&Sale&& con WHERE con.&&Id&& = &&Sale&&) WHERE &&PermissionRole&& = v_PermissionRoleTypeResponsible;
-- Перезаписать реальных пользователей в ответственных UPDATE &&SalePersonPermissionUpd&& SET &&User&& = (SELECT &&Author&& FROM &&Sale&& con WHERE con.&&Id&& = &&Sale&&), &&UserSecuritySetCacheId&& = (SELECT (&&Author&& | v_UserMask) FROM &&Sale&& con WHERE con.&&Id&& = &&Sale&&) WHERE &&PermissionRole&& = v_PermissionRoleAuthor;
INSERT INTO &&SalePersonPermission&& (&&Id&&, &&PermissionId&&, &&User&&, &&Group&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Sale&&, &&UserSecuritySetCacheId&&, &&Uid&&, &&InheritedFromNumber&&, &&OrganizationItemPosition&& ) SELECT NEXTVAL('G_SALEPERSONPERMISSION') AS &&Id&&, t.&&PermissionId&&, t.&&User&&, t.&&Group&&, t.&&PermissionRole&&, t.&&OrganizationItemEmployee&&, &&Sale&&, t.&&UserSecuritySetCacheId&&, UUID_GENERATE_V4() AS &&Uid&&, 1 AS &&InheritedFromNumber&&, t.&&OrganizationItemPosition&& FROM &&SalePersonPermissionUpd&& t WHERE &&Ins&& = 1;
/***************************************************************************************************** * * ВОЗМОЖНОСТИ * *****************************************************************************************************/ UPDATE &&RelationshipPersonPermission&& c SET &&InheritedFromNumber&& = &&InheritedFromNumber&& + 1 WHERE EXISTS( SELECT 1 FROM &&ContractorPersonPermissionUpd&& t WHERE CASE WHEN t.&&PermissionId&& = v_CRMContractorCreateElementPermissionId THEN v_CRMRelationshipCreateElementPermissionId WHEN t.&&PermissionId&& = v_CRMContractorIssuancePermissionId THEN v_CRMRelationshipIssuanceElementPermissionId WHEN t.&&PermissionId&& = v_ViewContractorPermissionId THEN v_ViewRelationshipPermissionId WHEN t.&&PermissionId&& = v_EditContractorPermissionId THEN v_EditRelationshipPermissionId WHEN t.&&PermissionId&& = v_FullContractorPermissionId THEN v_CRMRelationshipFullAccessPermissionId ELSE t.&&PermissionId&& END = c.&&PermissionId&& AND c.&&UserSecuritySetCacheId&& = CASE c.&&PermissionRole&& WHEN v_PermissionRoleAuthor THEN (SELECT &&CreationAuthor&& | v_UserMask FROM &&Contractor&& con WHERE con.&&Id&& = t.&&Contractor&&) WHEN v_PermissionRoleTypeResponsible THEN (SELECT &&Responsible&& | v_UserMask FROM &&Contractor&& con WHERE con.&&Id&& = t.&&Contractor&&) ELSE t.&&UserSecuritySetCacheId&& END AND c.&&PermissionRole&& = t.&&PermissionRole&& ) AND c.&&Relationship&& IN (SELECT ca.&&Id&& FROM &&Relationship&& ca WHERE ca.&&InheritPermissions&& = 1 AND ca.&&Contractor&& IS NOT NULL) AND c.&&InheritedFromNumber&& > 0;
-- Добавить недостающие привилегии к взаимоотношениям INSERT INTO &&RelationshipPersonPermUpd&& (&&PermissionId&&, &&User&&, &&Group&&, &&OrganizationItemPosition&&, &&UserSecuritySetCacheId&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Relationship&&, &&Ins&& ) SELECT c.&&PermissionId&&, m.&&UserID&& AS &&User&&, c.&&Group&&, c.&&OrganizationItemPosition&&, (m.&&UserID&& | v_UserMask) AS &&UserSecuritySetCacheId&&, c.&&PermissionRole&&, c.&&OrganizationItemEmployee&&, c.&&Relationship&&, 1 AS &&Ins&& FROM &&RelationshipUser&& m LEFT JOIN &&RelationshipPersonPermUpd&& c ON m.&&RelationshipID&& = c.&&Relationship&& WHERE &&PermissionRole&& = v_PermissionRoleTypeParticipantWork AND &&User&& = v_AdminUser AND m.&&Status&& = 0 AND &&Ins&& = 1 GROUP BY c.&&PermissionId&&, c.&&User&&, c.&&Group&&, c.&&PermissionRole&&, c.&&OrganizationItemEmployee&&, c.&&UserSecuritySetCacheId&&, c.&&OrganizationItemPosition&&, m.&&UserID&&, &&Relationship&&;
-- Добавить пермишены реальных пользователей для исполнителей INSERT INTO &&RelationshipPersonPermUpd&& (&&PermissionId&&, &&User&&, &&Group&&, &&OrganizationItemPosition&&, &&UserSecuritySetCacheId&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Relationship&&, &&Ins&& ) SELECT &&PermissionId&&, m.&&UserID&& AS &&User&&, &&Group&&, &&OrganizationItemPosition&&, (m.&&UserID&& | v_UserMask) AS &&UserSecuritySetCacheId&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Relationship&&, 1 AS &&Ins&& FROM &&RelationshipUser&& m LEFT JOIN &&RelationshipPersonPermUpd&& c ON m.&&RelationshipID&& = c.&&Relationship&& WHERE &&PermissionRole&& = v_PermissionRoleTypeInforms AND &&User&& = v_AdminUser AND m.&&Status&& = 1 AND &&Ins&& = 1 GROUP BY c.&&PermissionId&&, c.&&User&&, c.&&Group&&, c.&&PermissionRole&&, c.&&OrganizationItemEmployee&&, c.&&UserSecuritySetCacheId&&, c.&&OrganizationItemPosition&&, m.&&UserID&&, &&Relationship&&;
-- Перезаписать реальных пользователей в ответственных UPDATE &&RelationshipPersonPermUpd&& SET &&User&& = (SELECT &&CreationAuthor&& FROM &&Relationship&& con WHERE con.&&Id&& = &&Relationship&&), &&UserSecuritySetCacheId&& = (SELECT (&&CreationAuthor&& | v_UserMask) FROM &&Relationship&& con WHERE con.&&Id&& = &&Relationship&&) WHERE &&PermissionRole&& = v_PermissionRoleAuthor;
INSERT INTO &&RelationshipPersonPermission&& (&&Id&&, &&PermissionId&&, &&User&&, &&Group&&, &&PermissionRole&&, &&OrganizationItemEmployee&&, &&Relationship&&, &&UserSecuritySetCacheId&&, &&Uid&&, &&InheritedFromNumber&&, &&OrganizationItemPosition&& ) SELECT NEXTVAL('G_RELATIONSHIPPERSONPERMISSION') AS &&Id&&, t.&&PermissionId&&, t.&&User&&, t.&&Group&&, t.&&PermissionRole&&, t.&&OrganizationItemEmployee&&, &&Relationship&&, t.&&UserSecuritySetCacheId&&, UUID_GENERATE_V4() AS &&Uid&&, 1 AS &&InheritedFromNumber&&, t.&&OrganizationItemPosition&& FROM &&RelationshipPersonPermUpd&& t WHERE &&Ins&& = 1;
DELETE FROM &&ContractorPersonPermissionUpd&&; DELETE FROM &&ContactPersonPermissionUpd&&; DELETE FROM &&SalePersonPermissionUpd&&; DELETE FROM &&RelationshipPersonPermUpd&&;
