v_CRMSaleCreateElementPermissionId = '7DB77821-D6D3-4dd2-AD1B-798330506ADC';
v_CRMSaleFullAccessPermissionId ='DB60BB49-0DE1-46ee-8CE8-DCD59DB93351';

v_ViewLeadPermissionId ='C660E4B4-03BF-4315-9600-5086E47653B4';
v_EditLeadPermissionId ='AE298CD3-A16A-4B55-ACFC-545E4A0EBD48';
v_CRMLeadCreateElementPermissionId ='643FE44B-8192-4615-B853-106CD6F09EDE';
v_CRMLeadFullAccessPermissionId ='90BE803C-7857-4F2D-A8B4-129264504101';
v_CRMLeadIssuanceElementPermissionId ='E70A9AD1-80B2-4435-80E9-EF8E14B974CE';

