v_CRMRelationshipFullAccessPermissionId = '38A0AC5D-8D9C-4BB5-BDBA-A0E6CFD43C30';
v_PermissionRoleTypeParticipantWork  = '9A945D2E-BCFA-4AF4-8653-9A67A5ED6386';
v_PermissionRoleTypeInforms = '21888C0C-8BCA-4B26-AF13-4C497EECCED6';

delete from &&RelationshipPersonPermDel&&;

  select u.&&Id&& from &&User&& u where u.&&Uid&& = v_AdminUid 
        into v_AdminUser;

insert into &&LeadPersonPermissionDel&& (&&LeadId&&,&&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&, &&OrganizationItemEmployee&&,&&Lead&&,&&UserSecuritySetCacheId&&,&&OrganizationItemPosition&&, &&Child&&)
select c.&&Id&& as LeadId,t.&&PermissionId&&,t.&&User&&,t.&&Group&&,t.&&PermissionRole&&,t.&&OrganizationItemEmployee&&,&&Lead&&,t.&&UserSecuritySetCacheId&&,t.&&OrganizationItemPosition&& ,count(1) as &&Child&&
from &&LeadPersonPermission&& c
    left join &&TemplateLeadPermission&& t on c.&&PermissionId&&=t.&&PermissionId&& and c.&&UserSecuritySetCacheId&&=t.&&UserSecuritySetCacheId&&
    left join &&Category&& ca on ca.&&ContainerLeadPermission&&=t.&&ContainerLead&&
  where c.&&InheritedFromNumber&& > 0
    and t.&&Id&& is not null
    and c.&&Lead&&=$2
    and ca.&&Id&&=$1
group by c.&&Id&& ,t.&&PermissionId&&,t.&&User&&,t.&&Group&&,t.&&PermissionRole&&,t.&&OrganizationItemEmployee&&,&&Lead&&,t.&&UserSecuritySetCacheId&&,t.&&OrganizationItemPosition&&;


  update &&LeadPersonPermission&& c set &&InheritedFromNumber&&=&&InheritedFromNumber&&-(select max(ct.&&Child&&) from &&LeadPersonPermissionDel&& ct where ct.&&LeadId&& = c.&&Id&&) -- -ct.&&Child&&
  where &&Id&& in  (select c.&&Id&&
from &&LeadPersonPermission&& c
join &&LeadPersonPermissionDel&& ct on ct.&&LeadId&&=c.&&Id&&
where ct.&&LeadId&&=c.&&Id&&);

delete  from &&LeadPersonPermission&& where &&InheritedFromNumber&&<=0;

insert into &&RelationshipPersonPermDel&&(&&RelationshipId&&,&&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Relationship&&,&&UserSecuritySetCacheId&&,&&OrganizationItemPosition&&)
select c.&&Id&& as &&RelationshipId&&,c.&&PermissionId&&,t.&&User&&,t.&&Group&&,t.&&PermissionRole&&,t.&&OrganizationItemEmployee&&,&&Relationship&&,t.&&UserSecuritySetCacheId&&,t.&&OrganizationItemPosition&&
from &&RelationshipPersonPermission&& c
left join &&Relationship&& r on r.&&Id&&=c.&&Relationship&& and r.&&Lead&& = $2
left join &&LeadPersonPermissionDel&& t on
case
when t.&&PermissionId&&= v_CRMLeadCreateElementPermissionId then v_CRMRelationshipCreateElementPermissionId
when t.&&PermissionId&&= v_CRMLeadIssuanceElementPermissionId then v_CRMRelationshipIssuanceElementPermissionId
when t.&&PermissionId&&= v_ViewLeadPermissionId then v_ViewRelationshipPermissionId
when t.&&PermissionId&&= v_EditLeadPermissionId then v_EditRelationshipPermissionId
when t.&&PermissionId&&= v_CRMLeadFullAccessPermissionId then v_CRMRelationshipFullAccessPermissionId
else t.&&PermissionId&&
end =
c.&&PermissionId&& and c.&&UserSecuritySetCacheId&&=t.&&UserSecuritySetCacheId&&
where c.&&InheritedFromNumber&& > 0
and t.&&Lead&& = r.&&Lead&&
and t.&&LeadId&& is not null;

/*Удалить пермишены реальных пользователей для исполнителей*/
	insert into &&RelationshipPersonPermDel&& (&&RelationshipId&&,&&PermissionId&&,&&User&&,&&Group&&,&&OrganizationItemPosition&&,&&UserSecuritySetCacheId&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Relationship&&)
	select  &&Id&&,&&PermissionId&&,&&User&&,&&Group&&,&&OrganizationItemPosition&&,&&UserSecuritySetCacheId&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Relationship&&
	from &&RelationshipPersonPermission&& c
	where 
		&&InheritedFromNumber&& > 0
		and &&User&&!=v_AdminUser and
		&&PermissionRole&& =v_PermissionRoleTypeParticipantWork
		and exists (
			select &&RelationshipId&& from &&RelationshipPersonPermDel&& t where 
				&&PermissionRole&& =v_PermissionRoleTypeParticipantWork
				and c.&&PermissionId&&=t.&&permissionId&&
				and c.&&Relationship&&=t.&&Relationship&& );

/*Удалить пермишены реальных пользователей для исполнителей*/
	insert into &&RelationshipPersonPermDel&& (&&RelationshipId&&,&&PermissionId&&,&&User&&,&&Group&&,&&OrganizationItemPosition&&,&&UserSecuritySetCacheId&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Relationship&&)
	select  &&Id&&,&&PermissionId&&,&&User&&,&&Group&&,&&OrganizationItemPosition&&,&&UserSecuritySetCacheId&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Relationship&&
	from &&RelationshipPersonPermission&& c
	where 
		&&InheritedFromNumber&& > 0
		and &&User&&!=v_AdminUser and
		&&PermissionRole&& =v_PermissionRoleTypeInforms
		and exists (
			select &&RelationshipId&& from &&RelationshipPersonPermDel&& t where 
				&&PermissionRole&& =v_PermissionRoleTypeInforms
				and c.&&PermissionId&&=t.&&permissionId&&
				and c.&&Relationship&&=t.&&Relationship&& );

  update &&RelationshipPersonPermission&& c set &&InheritedFromNumber&&=c.&&InheritedFromNumber&&-(select max(ct.&&Child&&) from &&RelationshipPersonPermDel&& ct where c.&&Id&&=ct.&&RelationshipId&& )
    where c.&&Id&& in (select ct.&&RelationshipId&& from &&RelationshipPersonPermDel&& ct);

delete  from &&RelationshipPersonPermission&& where &&InheritedFromNumber&&<=0;
delete from &&RelationshipPersonPermDel&&;

end

$$
