select &&PermissionId&&,
&&User&&,&&Group&&,&&OrganizationItemPosition&&,&&UserSecuritySetCacheId&&,&&PermissionRole&&,cp.&&OrganizationItemEmployee&&,&&Lead&&
from  &&LeadPersonPermission&& cp  where cp.&&Uid&&=$1
into v_PermissionId, v_User, v_Group, v_OrganizationItemPosition, v_UserSecuritySetCacheId, v_PermissionRole, v_OrganizationItemEmployee, v_Lead;

