delete from &&RelationshipPersonPermDel&&;        


insert into &&RelationshipPersonPermDel&& (&&RelationshipId&&,&&PermissionId&&,&&UserSecuritySetCacheId&&,&&Relationship&&)
select c.&&Id&& as &&RelationshipId&&,c.&&PermissionId&&,c.&&UserSecuritySetCacheId&&,&&Relationship&&
from &&RelationshipPersonPermission&& c
inner join &&Relationship&& con on con.&&Id&&=c.&&Relationship&&
where  c.&&InheritedFromNumber&& > 0 and 
c.&&PermissionId&&=v_PermissionRelationshipId and c.&&UserSecuritySetCacheId&&=$2
and con.&&Sale&&=$3;


update &&RelationshipPersonPermission&& set &&InheritedFromNumber&&=&&InheritedFromNumber&&-1 where &&Id&& in
    (select c.&&Id&&
    from &&RelationshipPersonPermission&& c
    join &&RelationshipPersonPermDel&& ct on ct.&&RelationshipId&&=c.&&Id&&
    where ct.&&RelationshipId&&=c.&&Id&&);

    delete  from &&RelationshipPersonPermission&& where &&InheritedFromNumber&&<=0;
    delete from &&RelationshipPersonPermDel&&;
end

