            where  
             con.&&Id&&=&&RelationshipPersonPermission&&.&&Relationship&& 
             and case
                    when ct.&&PermissionId&&= v_CRMLeadCreateElementPermId then v_CRMRelationshipCreateElemPermId
                    when ct.&&PermissionId&&= v_CRMLeadIssuanceElemPermId then v_CRMRelIssuanceElemPermId
                    when ct.&&PermissionId&&= v_ViewLeadPermissionId then v_ViewRelationshipPermissionId
                    when ct.&&PermissionId&&= v_EditLeadPermissionId then v_EditRelationshipPermissionId
