where &&PermissionRole&& in (v_PermissionRoleTypeInforms) and &&User&&=v_adminUser 
group by c.&&PermissionId&& ,c.&&User&&,c.&&Group&&,c.&&PermissionRole&&,c.&&OrganizationItemEmployee&&,c.&&UserSecuritySetCacheId&& ,c.&&OrganizationItemPosition&&,m.&&Child&&,&&Contractor&&,c.&&InheritedFromNumber&&,c.&&Child&&;


/*Добавляем реальных информируемых пользователей при наличии фейковых*/
insert into &&ContractorPersonPermissionUpd&& (&&PermissionId&&,&&User&&
