where c.&&PermissionRole&& in (v_PermissionRoleTypeParticipantWork) and c.&&User&&=v_adminUser and c1.&&Id&& is null
group by c.&&PermissionId&& ,c.&&User&&,c.&&Group&&,c.&&PermissionRole&&,c.&&OrganizationItemEmployee&&,c.&&Id&&,c.&&UserSecuritySetCacheId&& ,c.&&OrganizationItemPosition&&,m.&&Child&&,c.&&Contractor&&,c.&&InheritedFromNumber&&;


