      ,m.&&UserID&&|v_usermask 
      ,c.&&PermissionRole&&
      ,c.&&OrganizationItemEmployee&&
      ,c.&&Relationship&&,c.&&InheritedFromNumber&&
	   from &&RelationshipUser&& m
left join &&RelationshippersonPermUpd&& c on m.&&RelationshipID&&=c.&&Relationship&&
where &&PermissionRole&& =v_PermissionRoleTypeInforms and &&User&&=v_adminUser and m.&&Status&&=1 
group by c.&&PermissionId&& ,c.&&User&&,c.&&Group&&,c.&&PermissionRole&&,c.&&OrganizationItemEmployee&&,c.&&UserSecuritySetCacheId&& ,c.&&OrganizationItemPosition&&,m.&&UserID&&,&&Relationship&&,c.&&InheritedFromNumber&&;



 insert into &&RelationshipPersonPermission&& (&&Id&&,&&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Relationship&&,&&UserSecuritySetCacheId&&,&&Uid&&,&&InheritedFromNumber&&,&&OrganizationItemPosition&&)
        select  nextval('G_RELATIONSHIPPERSONPERMISSION') &&Id&&,  t.&&PermissionId&& ,t.&&User&&,t.&&Group&&,t.&&PermissionRole&&,t.&&OrganizationItemEmployee&&,&&Relationship&&,t.&&UserSecuritySetCacheId&&,uuid_generate_v4() as &&Uid&&, &&InheritedFromNumber&&,t.&&OrganizationItemPosition&&
            from  &&RelationshippersonPermUpd&& t ;



        delete from &&TemplateContractorPermission&& a where &&User&& is null and &&Group&& is null and a.&&OrganizationItemPosition&& is null and a.&&OrganizationItemEmployee&& is null;
        delete from &&TemplateLeadPermission&& a where &&User&& is null and &&Group&& is null and a.&&OrganizationItemPosition&& is null and a.&&OrganizationItemEmployee&& is null;
        delete from &&ContactPersonPermission&& a where &&User&& is null and &&Group&& is null and a.&&OrganizationItemPosition&& is null and a.&&OrganizationItemEmployee&& is null;
        delete from &&ContractorPersonPermission&& a where &&User&& is null and &&Group&& is null and a.&&OrganizationItemPosition&& is null and a.&&OrganizationItemEmployee&& is null;
        delete from &&LeadPersonPermission&& a where &&User&& is null and &&Group&& is null and a.&&OrganizationItemPosition&& is null and a.&&OrganizationItemEmployee&& is null;
        delete from &&SalePersonPermission&& a where  &&User&& is null and &&Group&& is null and a.&&OrganizationItemPosition&& is null and a.&&OrganizationItemEmployee&& is null;
        delete from &&RelationshipPersonPermission&& a where &&User&& is null and &&Group&& is null and a.&&OrganizationItemPosition&& is null and a.&&OrganizationItemEmployee&& is null;

end

