(&&Id&&,&&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Contact&&,&&UserSecuritySetCacheId&&,&&OrganizationItemPosition&&,&&Ins&&)
