when t.&&PermissionId&&= v_EditContractorPermissionId then v_EditContactPermissionId
when t.&&PermissionId&&= v_FullContractorPermissionId then v_CRMContactFullAccessPermissionId
else t.&&PermissionId&&
end
,t.&&User&&,t.&&Group&&,t.&&PermissionRole&&,t.&&OrganizationItemEmployee&&,c.&&Id&& &&Contact&&,t.&&UserSecuritySetCacheId&&,t.&&OrganizationItemPosition&&,1 &&Ins&&
from &&Contact&& c
left join &&ContractorPersonPermissionUpd&& t on t.&&Contractor&&=c.&&Contractor&&
