from &&SalePersonPermissionUpd&& t where &&Ins&&=1;

truncate table &&TemplateContractorPermUpd&&;
truncate table &&ContractorPersonPermissionUpd&&;
truncate table &&SalePersonPermissionUpd&&;
truncate table &&ContactPersonPermissionUpd&&;

