     select  t.&&PermissionId&& ,t.&&User&&,t.&&Group&&,t.&&PermissionRole&&,t.&&OrganizationItemEmployee&&,c.&&Id&&,t.&&UserSecuritySetCacheId&& ,t.&&OrganizationItemPosition&&,1,count(1) as &&Child&&
     from &&Lead&& c
         join &&TemplateLeadPermUpd&& t on 1=1--  &&AddPermission&& = 0 and &&DelPermission&&!=1
         left outer join &&LeadPersonPermission&& cp on cp.&&Lead&&=c.&&Id&& and cp.&&PermissionId&&=t.&&PermissionId&& 
              and case cp.&&PermissionRole&& 
		                     when v_PermissionRoleAuthor then  (v_adminUser|v_usermask)
		                     when v_PermissionRoleTypeResponsible then  (v_adminUser|v_usermask)
		              ELSE cp.&&UserSecuritySetCacheId&&
		              end=t.&&UserSecuritySetCacheId&& 
              and cp.&&InheritedFromNumber&& > 0
        left join &&Category&& ca on  ca.&&ContainerLeadPermission&&=t.&&Lead&& 
     where
        c.&&InheritPermissions&&>=1
        and cp.&&Lead&& is null
        and c.&&Id&& in (select distinct c.&&Id&& from &&Lead&& c  left join &&M_Lead_Categories&& cc on cc.&&LeadId&&=c.&&Id&& where cc.&&CategoryId&& is null) 
     group by t.&&PermissionId&& ,t.&&User&&,t.&&Group&&,t.&&PermissionRole&&,t.&&OrganizationItemEmployee&&,c.&&Id&&,t.&&UserSecuritySetCacheId&& ,t.&&OrganizationItemPosition&&;


   /*Перезаписать реальных пользователей в ответственных */
      update &&LeadPersonPermissionUpd&& 
        set
        &&User&& = (select Responsible from &&Lead&& con where con.&&Id&&=&&Lead&&),
        &&UserSecuritySetCacheId&& = (select (Responsible | v_UserMask) from &&Lead&& con where con.&&Id&&=&&Lead&&)
      where PermissionRole=v_PermissionRoleTypeResp ; 

insert into &&LeadPersonPermission&& (&&Id&&,&&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Lead&&,&&UserSecuritySetCacheId&&,&&Uid&&,&&InheritedFromNumber&&,&&OrganizationItemPosition&&)
select  nextval('G_LeadPERSONPERMISSION') as &&Id&&,  t.&&PermissionId&& ,t.&&User&&,t.&&Group&&,t.&&PermissionRole&&,t.&&OrganizationItemEmployee&&,&&Lead&&,t.&&UserSecuritySetCacheId&&,uuid_generate_v4()  as &&Uid&&,&&Child&& as &&InheritedFromNumber&&,t.&&OrganizationItemPosition&&
from  &&LeadPersonPermissionUpd&& t where &&Ins&&=1;


insert into &&RelationshipPersonPermUpd&&( &&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Relationship&&,&&UserSecuritySetCacheId&&,&&OrganizationItemPosition&&,&&Ins&&)
select  c.&&PermissionId&&,t.&&User&&,t.&&Group&&,t.&&PermissionRole&&,t.&&OrganizationItemEmployee&&,ca.&&Id&& &&Relationship&&,t.&&UserSecuritySetCacheId&&,t.&&OrganizationItemPosition&&,0 &&Ins&&
from &&RelationshipPersonPermission&& c
left join &&Relationship&& r on r.&&Id&&=c.&&Relationship&& and r.&&Lead&& is not null
left join &&LeadPersonPermissionUpd&& t on

case
when t.&&PermissionId&&= v_CRMLeadCreateElementPermissionId then v_CRMRelationshipCreateElementPermissionId
when t.&&PermissionId&&= v_CRMLeadIssuanceElementPermissionId then v_CRMRelationshipIssuanceElementPermissionId
when t.&&PermissionId&&= v_ViewLeadPermissionId then v_ViewRelationshipPermissionId
when t.&&PermissionId&&= v_EditLeadPermissionId then v_EditRelationshipPermissionId
when t.&&PermissionId&&= v_CRMLeadFullAccessPermissionId then v_CRMRelationshipFullAccessPermissionId
else t.&&PermissionId&&
end =
c.&&PermissionId&& and c.&&UserSecuritySetCacheId&&=t.&&UserSecuritySetCacheId&&
left join &&Relationship&& ca on c.&&Relationship&&=ca.&&Id&& and ca.&&InheritPermissions&&=1
where  c.&&InheritedFromNumber&& > 0
and t.&&UserSecuritySetCacheId&& is not null ;

update &&RelationshipPersonPermission&& c set &&InheritedFromNumber&&=c.&&InheritedFromNumber&&+1
where exists (select &&Id&& from &&RelationshipPersonPermUpd&& t where t.&&PermissionId&&=c.&&PermissionId&& and t.&&UserSecuritySetCacheId&&=c.&&UserSecuritySetCacheId&& )   ;



insert into &&RelationshipPersonPermUpd&&  (&&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Relationship&&,&&UserSecuritySetCacheId&&,&&OrganizationItemPosition&&,&&Ins&&)

select
case
when t.&&PermissionId&&= v_CRMLeadCreateElementPermissionId then v_CRMRelationshipCreateElementPermissionId
when t.&&PermissionId&&= v_CRMLeadIssuanceElementPermissionId then v_CRMRelationshipIssuanceElementPermissionId
when t.&&PermissionId&&= v_ViewLeadPermissionId then v_ViewRelationshipPermissionId
when t.&&PermissionId&&= v_EditLeadPermissionId then v_EditRelationshipPermissionId
when t.&&PermissionId&&= v_CRMLeadFullAccessPermissionId then v_CRMRelationshipFullAccessPermissionId
else t.&&PermissionId&&
end 

,t.&&User&&,t.&&Group&&,t.&&PermissionRole&&,t.&&OrganizationItemEmployee&&,c.&&Id&& &&Relationship&&,t.&&UserSecuritySetCacheId&&,t.&&OrganizationItemPosition&&,1 &&Ins&&

from &&Relationship&& c
left join &&LeadPersonPermissionUpd&& t on t.&&Lead&&=c.&&Lead&& 
left outer join &&RelationshipPersonPermission&& cp on cp.&&Relationship&&=c.&&Id&& and cp.&&InheritedFromNumber&& > 0 and
case
when t.&&PermissionId&&= v_CRMLeadCreateElementPermissionId then v_CRMRelationshipCreateElementPermissionId
when t.&&PermissionId&&= v_CRMLeadIssuanceElementPermissionId then v_CRMRelationshipIssuanceElementPermissionId
when t.&&PermissionId&&= v_ViewLeadPermissionId then v_ViewRelationshipPermissionId
when t.&&PermissionId&&= v_EditLeadPermissionId then v_EditRelationshipPermissionId
when t.&&PermissionId&&= v_CRMLeadFullAccessPermissionId then v_CRMRelationshipFullAccessPermissionId
else t.&&PermissionId&&
end =

cp.&&PermissionId&& and cp.&&UserSecuritySetCacheId&&=t.&&UserSecuritySetCacheId&&
where  t.&&Lead&& is not null 
and c.&&InheritPermissions&&=1
and c.&&Lead&& is not null
and cp.&&Relationship&& is null;



insert into &&RelationshipPersonPermission&& (&&Id&&,&&PermissionId&&,&&User&&,&&Group&&,&&PermissionRole&&,&&OrganizationItemEmployee&&,&&Relationship&&,&&UserSecuritySetCacheId&&,&&Uid&&,&&InheritedFromNumber&&,&&OrganizationItemPosition&&)
select  nextval('G_RelationshipPERSONPERMISSION')  &&Id&&,t.&&PermissionId&& ,t.&&User&&,t.&&Group&&,t.&&PermissionRole&&,t.&&OrganizationItemEmployee&&,&&Relationship&&,t.&&UserSecuritySetCacheId&&,uuid_generate_v4() ,1 ,t.&&OrganizationItemPosition&&
from  &&RelationshipPersonPermUpd&& t where &&Ins&&=1;

delete from  &&RelationshipPersonPermUpd&&;
delete from &&LeadPersonPermissionUpd&&;
delete from &&TemplateLeadPermUpd&&;

end

$$
language plpgsql;
